export interface Question {
  id: string;
  question: string;
  questionFil?: string;
  options: string[];
  optionsFil?: string[];
  correctAnswer: number;
  explanation: string;
  explanationFil?: string;
  area: string;
  difficulty: 'easy' | 'medium' | 'hard';
  type: 'multiple-choice' | 'true-false' | 'identification';
}

export const questions: Question[] = [
  // === BASIC COMPETENCIES ===
  // Workplace Communication
  { id: 'bc-wc-01', question: 'What is the primary purpose of effective communication in the EMS workplace?', questionFil: 'Ano ang pangunahing layunin ng epektibong komunikasyon sa EMS workplace?', options: ['To impress supervisors', 'To ensure accurate information transfer for patient safety', 'To avoid documentation', 'To socialize with colleagues'], optionsFil: ['Upang-impress sa mga supervisor', 'Upang masiguro ang tumpak na paglipat ng impormasyon para sa kaligtasan ng pasyente', 'Upang iwasan ang dokumentasyon', 'Upang makipag-social sa mga kasamahan'], correctAnswer: 1, explanation: 'Effective communication in EMS is critical for patient safety. Miscommunication can lead to medical errors, incorrect treatments, or delayed care. Every member of the EMS team must be able to convey and receive information clearly and accurately.', explanationFil: 'Ang epektibong komunikasyon sa EMS ay kritikal para sa kaligtasan ng pasyente. Ang maling komunikasyon ay maaaring magdala ng mga medikal na pagkakamali, maling paggamot, o naantala na pangangalaga.', area: 'workplace-communication', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'bc-wc-02', question: 'Which communication technique involves restating what the speaker said to confirm understanding?', questionFil: 'Aling teknik sa komunikasyon ang naglalaman ng pag-uulit ng sinabi ng nagsasalita upang kumpirmahin ang pag-unawa?', options: ['Active listening', 'Reflective listening', 'Nonverbal communication', 'Therapeutic silence'], correctAnswer: 1, explanation: 'Reflective listening involves restating or paraphrasing what the speaker has said to confirm understanding. This technique helps ensure that the message was received correctly and demonstrates to the speaker that they are being heard.', explanationFil: 'Ang reflective listening ay naglalaman ng pag-uulit o pag-paraphrase ng sinabi ng nagsasalita upang kumpirmahin ang pag-unawa.', area: 'workplace-communication', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'bc-wc-03', question: 'When giving a radio report to the hospital, the EMS provider should:', questionFil: 'Kapag nagbibigay ng radio report sa ospital, ang EMS provider ay dapat:', options: ['Use medical jargon extensively', 'Speak clearly and concisely using standard terminology', 'Skip patient information if in a hurry', 'Whisper to maintain confidentiality'], correctAnswer: 1, explanation: 'Radio reports should be clear, concise, and use standard medical terminology to ensure the receiving facility understands the patient condition and can prepare accordingly.', area: 'workplace-communication', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'bc-wc-04', question: 'The SBAR communication tool stands for:', questionFil: 'Ang SBAR communication tool ay nangangahulugan ng:', options: ['Situation, Background, Assessment, Recommendation', 'Symptoms, Breathing, Airway, Response', 'Safety, Body, Assessment, Rescue', 'Standard, Basic, Assessment, Report'], correctAnswer: 0, explanation: 'SBAR is a standardized communication framework used in healthcare: Situation (what is happening now), Background (relevant clinical background), Assessment (your assessment of the situation), Recommendation (what you recommend).', area: 'workplace-communication', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'bc-wc-05', question: 'Nonverbal communication accounts for approximately what percentage of total communication?', options: ['10%', '30%', '55%', '90%'], correctAnswer: 2, explanation: 'Research suggests that nonverbal communication (body language, facial expressions, tone of voice) accounts for approximately 55% or more of total communication, making it crucial in patient interactions.', area: 'workplace-communication', difficulty: 'medium', type: 'multiple-choice' },

  // Teamwork
  { id: 'bc-tw-01', question: 'In EMS team dynamics, the team leader is responsible for:', questionFil: 'Sa dynamics ng EMS team, ang team leader ay responsable sa:', options: ['Performing all procedures alone', 'Coordinating team actions and making clinical decisions', 'Delegating all tasks to the newest member', 'Avoiding communication with team members'], correctAnswer: 1, explanation: 'The EMS team leader coordinates team actions, makes clinical decisions, ensures all tasks are completed, and maintains communication. They do not perform all tasks alone but rather direct the team effectively.', area: 'teamwork', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'bc-tw-02', question: 'What is "closed-loop communication" in EMS?', questionFil: 'Ano ang "closed-loop communication" sa EMS?', options: ['Communication that ends with a disagreement', 'A communication process where the receiver repeats back the order to confirm', 'Communication without feedback', 'One-way communication from leader to team'], correctAnswer: 1, explanation: 'Closed-loop communication requires the receiver to repeat back the order or instruction to the sender, confirming understanding. This reduces errors in high-stress EMS situations.', area: 'teamwork', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'bc-tw-03', question: 'When a team member identifies a potential error during a procedure, they should:', options: ['Ignore it if the team leader is senior', 'Speak up immediately using the two-challenge rule if necessary', 'Wait until after the call to mention it', 'Write it down for the report only'], correctAnswer: 1, explanation: 'Patient safety requires all team members to speak up about potential errors. The two-challenge rule allows a team member to challenge a decision up to twice if they believe patient safety is at risk.', area: 'teamwork', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'bc-tw-04', question: 'Crew resource management (CRM) in EMS focuses on:', options: ['Managing equipment inventory', 'Optimizing team performance through communication, situational awareness, and decision-making', 'Reducing the number of team members', 'Increasing response times'], correctAnswer: 1, explanation: 'CRM focuses on optimizing team performance by improving communication, situational awareness, decision-making, and teamwork. It originated in aviation and has been adapted for healthcare and EMS.', area: 'teamwork', difficulty: 'hard', type: 'multiple-choice' },
  { id: 'bc-tw-05', question: 'The "STEREO" acronym in EMS teamwork stands for:', options: ['Situation, Team, Equipment, Resources, Environment, Outcomes', 'Safety, Treatment, Evacuation, Rescue, Emergency, Operations', 'Standard, Technique, Execution, Response, Evaluation, Observation', 'It is not a standard EMS teamwork acronym'], correctAnswer: 3, explanation: 'STEREO is not a standard EMS teamwork acronym. This question tests critical thinking - not every acronym presented is valid, and EMS providers should verify information from reliable sources.', area: 'teamwork', difficulty: 'hard', type: 'multiple-choice' },

  // Professionalism
  { id: 'bc-pr-01', question: 'Which of the following best demonstrates professionalism in EMS?', options: ['Arriving late occasionally', 'Maintaining patient confidentiality and dignity at all times', 'Discussing patient details on social media', 'Refusing to assist with non-emergency calls'], correctAnswer: 1, explanation: 'Professionalism in EMS includes maintaining patient confidentiality and dignity, being punctual, providing equal care regardless of circumstances, and adhering to ethical standards at all times.', area: 'professionalism', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'bc-pr-02', question: 'Patient confidentiality is protected by which law in the Philippines?', questionFil: 'Ang confidentiality ng pasyente ay protektado ng aling batas sa Pilipinas?', options: ['Labor Code', 'Data Privacy Act of 2012 (Republic Act No. 10173)', 'Civil Code only', 'No specific law'], correctAnswer: 1, explanation: 'The Data Privacy Act of 2012 (RA 10173) protects personal information including health data. EMS providers must maintain patient confidentiality and only share information with authorized personnel involved in patient care.', area: 'professionalism', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'bc-pr-03', question: 'An EMS provider who reports unsafe practices is exercising:', options: ['Insubordination', 'Whistleblowing and professional responsibility', 'Negligence', 'Unprofessional behavior'], correctAnswer: 1, explanation: 'Reporting unsafe practices is a professional responsibility. Whistleblowing protects patients and colleagues, and it is a duty of ethical EMS professionals to report conditions that may harm others.', area: 'professionalism', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'bc-pr-04', question: 'Ethical decision-making in EMS requires:', options: ['Following orders without question', 'Balancing beneficence, non-maleficence, autonomy, and justice', 'Always prioritizing speed over accuracy', 'Avoiding difficult decisions'], correctAnswer: 1, explanation: 'Ethical decision-making in EMS involves balancing four key principles: beneficence (doing good), non-maleficence (do no harm), autonomy (respecting patient choices), and justice (fair and equal treatment).', area: 'professionalism', difficulty: 'hard', type: 'multiple-choice' },
  { id: 'bc-pr-05', question: 'Continuing education in EMS is important because:', options: ['It is only required for recertification', 'Medical knowledge and protocols constantly evolve', 'It replaces field experience', 'It is optional for experienced providers'], correctAnswer: 1, explanation: 'Continuing education is essential because medical knowledge, protocols, and best practices constantly evolve. EMS providers must stay current to provide the best possible patient care.', area: 'professionalism', difficulty: 'easy', type: 'multiple-choice' },

  // Occupational Safety and Health
  { id: 'bc-osh-01', question: 'Standard precautions in EMS require treating all bodily fluids as:', options: ['Clean', 'Potentially infectious', 'Non-hazardous if the patient looks healthy', 'Only dangerous if visibly contaminated'], correctAnswer: 1, explanation: 'Standard precautions require treating ALL blood and bodily fluids as potentially infectious, regardless of the patient appearance or known diagnosis. This protects the EMS provider from exposure to bloodborne pathogens.', area: 'occupational-safety', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'bc-osh-02', question: 'The minimum PPE required when handling a bleeding patient includes:', questionFil: 'Ang pinakamababang PPE na kailangan kapag humahawak ng dumudugang pasyente ay kinabibilangan ng:', options: ['Gown only', 'Gloves at minimum; mask and eye protection if splash risk', 'No PPE if the wound is small', 'Only hand sanitizer after contact'], correctAnswer: 1, explanation: 'At minimum, gloves are required. If there is a risk of splash or spray of blood or body fluids, a mask and eye protection should also be worn. Full PPE may include gown, gloves, mask, and eye protection depending on the situation.', area: 'occupational-safety', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'bc-osh-03', question: 'If an EMS provider experiences a needlestick injury, the first action should be:', options: ['Continue patient care', 'Wash the wound immediately and report the incident', 'Ignore it if the patient appears healthy', 'Apply a bandage and forget about it'], correctAnswer: 1, explanation: 'After a needlestick injury, immediately wash the wound with soap and water, report the incident to the designated officer, and seek medical evaluation. Prompt reporting and treatment can prevent serious infections.', area: 'occupational-safety', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'bc-osh-04', question: 'Proper body mechanics when lifting a patient include:', options: ['Bending at the waist', 'Keeping the back straight and lifting with the legs', 'Twisting the torso while lifting', 'Lifting with arms extended away from the body'], correctAnswer: 1, explanation: 'Proper body mechanics require keeping the back straight, bending at the knees, lifting with the legs, keeping the load close to the body, and avoiding twisting. This prevents musculoskeletal injuries.', area: 'occupational-safety', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'bc-osh-05', question: 'Critical incident stress management (CISM) is designed to:', options: ['Punish staff for emotional reactions', 'Help EMS providers cope with traumatic stress from critical incidents', 'Eliminate all workplace stress', 'Replace regular work schedules'], correctAnswer: 1, explanation: 'CISM is a comprehensive, systematic approach to help emergency personnel cope with traumatic stress. It includes interventions like debriefings, defusings, and individual support to promote psychological well-being.', area: 'occupational-safety', difficulty: 'medium', type: 'multiple-choice' },

  // Problem Solving
  { id: 'bc-ps-01', question: 'The first step in systematic problem-solving in EMS is:', options: ['Implementing a solution immediately', 'Identifying and defining the problem', 'Assigning blame for the situation', 'Skipping assessment to save time'], correctAnswer: 1, explanation: 'The first step in systematic problem-solving is to identify and clearly define the problem. Without properly understanding the problem, any solution may be ineffective or even harmful.', area: 'problem-solving', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'bc-ps-02', question: 'When faced with an unfamiliar medical situation, the EMS provider should:', options: ['Guess the treatment', 'Fall back on basic assessment skills and protocols, and request assistance', 'Refuse to treat the patient', 'Delay all care until a physician arrives'], correctAnswer: 1, explanation: 'When encountering unfamiliar situations, EMS providers should rely on their fundamental assessment skills, follow established protocols, and request medical direction or additional resources as needed.', area: 'problem-solving', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'bc-ps-03', question: 'Critical thinking in EMS involves:', options: ['Following protocols without deviation', 'Analyzing situations, considering alternatives, and making reasoned decisions', 'Relying solely on intuition', 'Avoiding complex decisions'], correctAnswer: 1, explanation: 'Critical thinking involves analyzing situations systematically, considering multiple possibilities, weighing evidence, and making reasoned decisions based on available information and training.', area: 'problem-solving', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'bc-ps-04', question: 'Triage decision-making requires:', options: ['Treating the most vocal patients first', 'Prioritizing patients based on severity of injury and likelihood of survival', 'Treating patients in order of arrival', 'Treating only the walking wounded'], correctAnswer: 1, explanation: 'Triage prioritizes patients based on severity and survivability. The goal is to do the greatest good for the greatest number, allocating resources to those who need them most and can benefit from them.', area: 'problem-solving', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'bc-ps-05', question: 'When equipment fails during an emergency, the EMS provider should:', options: ['Stop all care immediately', 'Implement backup plans and adapt using available resources', 'Blame the equipment manager', 'Wait for replacement equipment before continuing'], correctAnswer: 1, explanation: 'EMS providers must be adaptable and resourceful. When equipment fails, implement backup plans, use alternative methods, and continue providing care within your capabilities while requesting replacement equipment.', area: 'problem-solving', difficulty: 'easy', type: 'multiple-choice' },

  // Workplace Documentation
  { id: 'bc-wd-01', question: 'The EMS patient care report (PCR) serves as:', options: ['An optional note for personal reference', 'A legal document that records patient assessment, treatment, and response', 'A form that only needs completion for serious calls', 'A document only seen by the EMS provider'], correctAnswer: 1, explanation: 'The PCR is a legal medical document that records all aspects of patient contact including assessment findings, treatments provided, patient response, and other relevant information. It is used for continuity of care, legal protection, and quality improvement.', area: 'workplace-documentation', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'bc-wd-02', question: 'When documenting on a PCR, the EMS provider should:', options: ['Use vague language to avoid legal issues', 'Document objectively, accurately, and completely using specific measurements', 'Leave blank spaces for later completion', 'Use abbreviations not approved by the agency'], correctAnswer: 1, explanation: 'Documentation should be objective, accurate, complete, and use specific measurements and descriptions. Use only approved abbreviations. Never leave blank spaces - draw a line through unused areas.', area: 'workplace-documentation', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'bc-wd-03', question: 'The minimum data set for an EMS PCR includes:', options: ['Patient name only', 'Patient information, times, assessment findings, treatment, and response', 'Only the chief complaint', 'Only the treatment given'], correctAnswer: 1, explanation: 'A complete PCR must include patient demographics, times (dispatch, arrival, transport, etc.), assessment findings, treatment provided, patient response, and narrative description of the call.', area: 'workplace-documentation', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'bc-wd-04', question: 'If a medication error occurs, the EMS provider should:', options: ['Hide the error to avoid discipline', 'Document the error, report it, and monitor the patient closely', 'Only tell the patient if they ask', 'Discontinue the PCR for that call'], correctAnswer: 1, explanation: 'Medication errors must be documented honestly, reported through proper channels, and the patient must be monitored closely. Attempting to hide errors is unethical and can cause further patient harm.', area: 'workplace-documentation', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'bc-wd-05', question: 'When a patient refuses treatment, the EMS provider must document:', options: ['Nothing, since no treatment was given', 'The refusal, patient capacity assessment, risks explained, and signatures', 'Only the patient name', 'Just the time of refusal'], correctAnswer: 1, explanation: 'Against medical advice (AMA) documentation must include assessment of patient capacity, specific risks explained to the patient, the patient understanding of those risks, signatures, and witness information.', area: 'workplace-documentation', difficulty: 'hard', type: 'multiple-choice' },

  // === COMMON COMPETENCIES ===
  // Infection Control
  { id: 'cc-ic-01', question: 'The most effective method of preventing the spread of infection is:', options: ['Wearing a mask at all times', 'Proper hand hygiene', 'Using antibiotics', 'Wearing gloves only'], correctAnswer: 1, explanation: 'Proper hand hygiene is the single most effective method of preventing the spread of infection. This includes washing with soap and water or using alcohol-based hand sanitizer when hands are not visibly soiled.', area: 'infection-control', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'cc-ic-02', question: 'Personal protective equipment (PPE) should be donned in which order?', options: ['Gloves, mask, gown, eye protection', 'Gown, mask, eye protection, gloves', 'Mask, gloves, gown, eye protection', 'Eye protection, gown, mask, gloves'], correctAnswer: 1, explanation: 'The correct donning order is: gown first, then mask, then eye protection, then gloves last (gloves go over gown cuffs). This sequence minimizes contamination risk.', area: 'infection-control', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'cc-ic-03', question: 'The chain of infection requires all of the following EXCEPT:', options: ['Infectious agent', 'Reservoir', 'Portal of entry', 'Antibiotic resistance'], correctAnswer: 3, explanation: 'The chain of infection includes: infectious agent, reservoir, portal of exit, mode of transmission, portal of entry, and susceptible host. Antibiotic resistance is not part of the chain of infection.', area: 'infection-control', difficulty: 'hard', type: 'multiple-choice' },
  { id: 'cc-ic-04', question: 'Bloodborne pathogens of primary concern to EMS providers include:', options: ['Common cold virus and flu', 'Hepatitis B, Hepatitis C, and HIV', 'E. coli and Salmonella', 'Strep throat and pneumonia'], correctAnswer: 1, explanation: 'The three bloodborne pathogens of primary concern in EMS are Hepatitis B virus (HBV), Hepatitis C virus (HCV), and Human Immunodeficiency Virus (HIV). These can be transmitted through occupational exposure to blood and body fluids.', area: 'infection-control', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'cc-ic-05', question: 'Proper removal of contaminated gloves involves:', options: ['Pulling them off quickly by the fingertips', 'Grasping the outside of one glove with the other gloved hand, then using the bare finger to remove the second glove', 'Cutting them off with scissors', 'Asking someone else to remove them'], correctAnswer: 1, explanation: 'To safely remove gloves: grasp the outside of one glove near the wrist with the other gloved hand, peel it off inside out. Then insert a bare finger inside the second glove and peel it off inside out, containing the contamination.', area: 'infection-control', difficulty: 'medium', type: 'multiple-choice' },

  // Vital Signs
  { id: 'cc-vs-01', question: 'Normal adult resting heart rate is:', options: ['40-60 bpm', '60-100 bpm', '100-120 bpm', '120-140 bpm'], correctAnswer: 1, explanation: 'The normal adult resting heart rate is 60-100 beats per minute. Rates below 60 are bradycardia, and rates above 100 are tachycardia in adults.', area: 'vital-signs', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'cc-vs-02', question: 'Normal adult blood pressure is approximately:', options: ['90/60 mmHg', '120/80 mmHg', '140/90 mmHg', '160/100 mmHg'], correctAnswer: 1, explanation: 'Normal adult blood pressure is approximately 120/80 mmHg. Systolic pressure below 90 mmHg may indicate hypotension, while sustained readings above 140/90 mmHg indicate hypertension.', area: 'vital-signs', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'cc-vs-03', question: 'Normal adult respiratory rate is:', options: ['6-10 breaths per minute', '12-20 breaths per minute', '24-30 breaths per minute', '30-40 breaths per minute'], correctAnswer: 1, explanation: 'Normal adult respiratory rate is 12-20 breaths per minute. Rates below 12 indicate bradypnea, and rates above 20 indicate tachypnea in resting adults.', area: 'vital-signs', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'cc-vs-04', question: 'Normal SpO2 (oxygen saturation) for a healthy adult is:', options: ['85-90%', '90-94%', '95-100%', '100-105%'], correctAnswer: 2, explanation: 'Normal SpO2 for a healthy adult is 95-100%. Values below 94% may indicate hypoxemia and require supplemental oxygen. Values below 90% indicate significant hypoxia.', area: 'vital-signs', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'cc-vs-05', question: 'When taking a blood pressure, the first sound heard through the stethoscope is the:', options: ['Diastolic pressure', 'Systolic pressure', 'Mean arterial pressure', 'Pulse pressure'], correctAnswer: 1, explanation: 'The first Korotkoff sound heard when gradually releasing the cuff pressure corresponds to the systolic pressure. The point at which the sounds disappear corresponds to the diastolic pressure.', area: 'vital-signs', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'cc-vs-06', question: 'The Glasgow Coma Scale (GCS) assesses:', options: ['Only pupil response', 'Eye opening, verbal response, and motor response', 'Blood pressure and heart rate', 'Respiratory effort only'], correctAnswer: 1, explanation: 'The GCS assesses three areas: Eye Opening (1-4), Verbal Response (1-5), and Motor Response (1-6). Total score ranges from 3-15. A score of 8 or below indicates severe brain injury.', area: 'vital-signs', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'cc-vs-07', question: 'A normal body temperature is:', options: ['35.0°C', '36.5-37.5°C', '38.5°C', '40.0°C'], correctAnswer: 1, explanation: 'Normal body temperature is 36.5-37.5°C (97.7-99.5°F). Temperatures above 37.5°C may indicate fever, while temperatures below 35°C indicate hypothermia.', area: 'vital-signs', difficulty: 'easy', type: 'multiple-choice' },

  // Patient Assessment
  { id: 'cc-pa-01', question: 'The first step in patient assessment is:', options: ['Taking vital signs', 'Determining scene safety', 'Obtaining a SAMPLE history', 'Performing a physical exam'], correctAnswer: 1, explanation: 'Before any patient contact, the EMS provider must ensure scene safety. An unsafe scene puts both the provider and patient at risk. Always assess for hazards before approaching the patient.', area: 'patient-assessment', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'cc-pa-02', question: 'The SAMPLE history acronym stands for:', options: ['Signs/Symptoms, Allergies, Medications, Past medical history, Last oral intake, Events leading up to', 'Size, Area, Movement, Pain, Location, Extent', 'Standard, Assessment, Method, Plan, Lab, Evaluation', 'Simple, Approach, Monitor, Protect, Leave, Evacuate'], correctAnswer: 0, explanation: 'SAMPLE: Signs/Symptoms, Allergies, Medications, Past medical history, Last oral intake, Events leading up to the illness/injury. This is the standard history-taking format in EMS.', area: 'patient-assessment', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'cc-pa-03', question: 'The OPQRST acronym is used to assess:', options: ['Level of consciousness', 'Pain characteristics', 'Breathing difficulty', 'Blood glucose level'], correctAnswer: 1, explanation: 'OPQRST assesses pain: Onset (when did it start), Provocation (what makes it worse/better), Quality (description of pain), Radiation (does it spread), Severity (0-10 scale), Time (duration/pattern).', area: 'patient-assessment', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'cc-pa-04', question: 'The AVPU scale is used to assess:', options: ['Pain severity', 'Level of consciousness', 'Respiratory distress', 'Circulatory status'], correctAnswer: 1, explanation: 'AVPU: Alert (patient is awake and responsive), Verbal (responds to verbal stimuli), Pain (responds only to painful stimuli), Unresponsive (no response to any stimuli). It is a rapid consciousness assessment tool.', area: 'patient-assessment', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'cc-pa-05', question: 'During the primary assessment, you should check:', options: ['All body systems in detail', 'Airway, Breathing, and Circulation (ABCs)', 'Only the chief complaint', 'Only vital signs'], correctAnswer: 1, explanation: 'The primary assessment focuses on identifying and treating life-threatening conditions by checking Airway, Breathing, and Circulation (the ABCs). This must be completed before moving to the secondary assessment.', area: 'patient-assessment', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'cc-pa-06', question: 'DCAP-BTLS is used during which part of the assessment?', options: ['Primary assessment', 'Secondary assessment (physical exam)', 'Patient history', 'Scene size-up'], correctAnswer: 1, explanation: 'DCAP-BTLS (Deformities, Contusions, Abrasions, Punctures/Penetrations, Burns, Tenderness, Lacerations, Swelling) is a memory aid used during the secondary assessment physical exam to systematically check for injuries.', area: 'patient-assessment', difficulty: 'medium', type: 'multiple-choice' },

  // Basic Anatomy
  { id: 'cc-ba-01', question: 'How many bones are in the adult human body?', options: ['186', '206', '226', '256'], correctAnswer: 1, explanation: 'The adult human body has 206 bones. Infants have approximately 270 bones, but many fuse together as the body matures.', area: 'basic-anatomy', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'cc-ba-02', question: 'The largest organ in the human body is:', options: ['Liver', 'Brain', 'Skin', 'Lungs'], correctAnswer: 2, explanation: 'The skin is the largest organ of the human body, covering approximately 1.5-2 square meters in adults. It serves as a barrier against infection and helps regulate body temperature.', area: 'basic-anatomy', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'cc-ba-03', question: 'The heart is located in which cavity?', options: ['Abdominal cavity', 'Cranial cavity', 'Thoracic cavity (mediastinum)', 'Pelvic cavity'], correctAnswer: 2, explanation: 'The heart is located in the thoracic cavity, specifically in the mediastinum - the central compartment between the lungs. It sits slightly left of center.', area: 'basic-anatomy', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'cc-ba-04', question: 'The diaphragm separates which two body cavities?', options: ['Cranial and spinal', 'Thoracic and abdominal', 'Abdominal and pelvic', 'Dorsal and ventral'], correctAnswer: 1, explanation: 'The diaphragm is a muscular partition that separates the thoracic cavity (containing heart and lungs) from the abdominal cavity (containing digestive organs). It is the primary muscle of respiration.', area: 'basic-anatomy', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'cc-ba-05', question: 'Which blood cells are responsible for oxygen transport?', options: ['White blood cells', 'Platelets', 'Red blood cells (erythrocytes)', 'Plasma cells'], correctAnswer: 2, explanation: 'Red blood cells (erythrocytes) contain hemoglobin, which binds and transports oxygen throughout the body. White blood cells fight infection, and platelets help with clotting.', area: 'basic-anatomy', difficulty: 'easy', type: 'multiple-choice' },

  // Medical Terminology
  { id: 'cc-mt-01', question: 'The prefix "brady-" means:', options: ['Fast', 'Slow', 'Large', 'Small'], correctAnswer: 1, explanation: 'The prefix "brady-" means slow. Examples: bradycardia (slow heart rate), bradypnea (slow breathing). The opposite prefix is "tachy-" meaning fast.', area: 'medical-terminology', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'cc-mt-02', question: 'The suffix "-itis" means:', options: ['Inflammation', 'Surgical removal', 'Disease', 'Tumor'], correctAnswer: 0, explanation: 'The suffix "-itis" means inflammation. Examples: appendicitis (inflammation of the appendix), bronchitis (inflammation of the bronchi), arthritis (inflammation of joints).', area: 'medical-terminology', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'cc-mt-03', question: 'The prefix "hyper-" means:', options: ['Below normal', 'Above normal/excessive', 'Slow', 'Fast'], correctAnswer: 1, explanation: 'The prefix "hyper-" means above normal or excessive. Examples: hypertension (high blood pressure), hyperglycemia (high blood sugar). The opposite is "hypo-" meaning below normal.', area: 'medical-terminology', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'cc-mt-04', question: '"Ischemia" refers to:', options: ['Infection of tissue', 'Inadequate blood supply to tissue', 'Excessive bleeding', 'Tissue death'], correctAnswer: 1, explanation: 'Ischemia refers to inadequate blood supply to tissue, resulting in oxygen deprivation. If ischemia persists, it can lead to infarction (tissue death). This is critical in conditions like heart attacks and strokes.', area: 'medical-terminology', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'cc-mt-05', question: 'The term "afebrile" means:', options: ['Having a fever', 'Without fever', 'Having an infection', 'Low body temperature'], correctAnswer: 1, explanation: '"Afebrile" means without fever. The prefix "a-" means without, and "febrile" relates to fever. Normal body temperature without fever is afebrile.', area: 'medical-terminology', difficulty: 'medium', type: 'multiple-choice' },

  // Body Mechanics
  { id: 'cc-bm-01', question: 'The recommended weight limit for a single EMS provider to lift is:', options: ['25 lbs', '50 lbs', '75 lbs', 'No limit'], correctAnswer: 0, explanation: 'The general recommendation is that a single provider should not lift more than 25 lbs alone. For heavier loads, use additional personnel, mechanical lifts, or proper team lifting techniques.', area: 'body-mechanics', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'cc-bm-02', question: 'When carrying a stretcher, EMS providers should:', options: ['Walk at different speeds', 'Communicate and walk in sync', 'Run whenever possible', 'Only the team leader should carry'], correctAnswer: 1, explanation: 'When carrying a stretcher, all providers must communicate and walk in synchronized steps to maintain balance and prevent the stretcher from tilting or the patient from falling.', area: 'body-mechanics', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'cc-bm-03', question: 'The power grip involves:', options: ['Holding with fingertips only', 'Grasping with the entire hand, palm facing the object', 'Using only the thumb and index finger', 'Holding with arms fully extended'], correctAnswer: 1, explanation: 'The power grip involves grasping an object with the entire hand, with the palm facing the object. This provides maximum strength and control, reducing the risk of dropping the patient or equipment.', area: 'body-mechanics', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'cc-bm-04', question: 'When pushing a heavy object, you should:', options: ['Push with your back', 'Push from a position with your elbows bent and close to your body', 'Push with arms fully extended', 'Push from above shoulder height'], correctAnswer: 1, explanation: 'When pushing, keep your elbows bent and close to your body, use your leg muscles, and push from between waist and shoulder height. This provides maximum force while protecting your back.', area: 'body-mechanics', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'cc-bm-05', question: 'The reach and pull technique is used for:', options: ['Lifting heavy boxes', 'Moving a patient from the ground to a stretcher', 'Opening doors', 'Climbing stairs'], correctAnswer: 1, explanation: 'The reach and pull technique is used when moving a patient from the ground to a stretcher. The provider kneels, reaches under the patient, and pulls the patient onto the stretcher while maintaining proper body mechanics.', area: 'body-mechanics', difficulty: 'medium', type: 'multiple-choice' },

  // Communication Procedures
  { id: 'cc-cp-01', question: 'When communicating with a patient who does not speak your language, you should:', options: ['Speak louder', 'Use simple terms, gestures, and seek an interpreter', 'Skip communication and proceed with assessment', 'Use medical jargon to be precise'], correctAnswer: 1, explanation: 'When facing a language barrier, use simple terms, gestures, visual aids, and seek a qualified interpreter. Speaking louder does not help and can be perceived as aggressive. Never skip communication.', area: 'communication-procedures', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'cc-cp-02', question: 'Therapeutic communication with an anxious patient includes:', options: ['Telling them to calm down', 'Using a calm voice, maintaining eye contact, and acknowledging their feelings', 'Ignoring their anxiety', 'Giving false reassurance'], correctAnswer: 1, explanation: 'Therapeutic communication involves using a calm, reassuring voice, maintaining appropriate eye contact, actively listening, and acknowledging the patient feelings without minimizing them.', area: 'communication-procedures', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'cc-cp-03', question: 'When transferring patient care to another provider, you should:', options: ['Just hand over the paperwork', 'Give a verbal report covering essential patient information and treatments', 'Only mention the chief complaint', 'Let the receiving provider figure it out'], correctAnswer: 1, explanation: 'A proper patient handoff includes a verbal report covering patient identification, chief complaint, assessment findings, treatments provided, patient response, and any pending issues. Use a structured format like SBAR.', area: 'communication-procedures', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'cc-cp-04', question: 'When using the radio to communicate with medical direction, you should:', options: ['Use informal language', 'Use clear, concise, standardized terminology', 'Leave the radio on for extended periods', 'Only call for critical patients'], correctAnswer: 1, explanation: 'Radio communications should use clear, concise, and standardized medical terminology. Follow your agency communication protocols, and be professional and organized in your transmissions.', area: 'communication-procedures', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'cc-cp-05', question: 'A key principle of therapeutic communication is:', options: ['Providing all the answers', 'Active listening and empathic responding', 'Avoiding eye contact', 'Interrupting to save time'], correctAnswer: 1, explanation: 'Active listening and empathic responding are key principles of therapeutic communication. This involves giving full attention, reflecting feelings, and responding with understanding rather than just providing answers.', area: 'communication-procedures', difficulty: 'easy', type: 'multiple-choice' },

  // Documentation Procedures
  { id: 'cc-dp-01', question: 'When documenting times on a PCR, you should use:', options: ['Approximate times', 'Exact times using the 24-hour clock', 'Only the date', 'The time you think is most convenient'], correctAnswer: 1, explanation: 'All times on a PCR should be documented using exact times in the 24-hour clock format. This ensures accuracy and prevents confusion between AM and PM times.', area: 'documentation-procedures', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'cc-dp-02', question: 'The narrative section of a PCR should be:', options: ['Brief and vague', 'Detailed, objective, and chronological', 'Written in first person with personal opinions', 'Left blank if the call was routine'], correctAnswer: 1, explanation: 'The narrative should be detailed, objective, and presented in chronological order. It should describe what you saw, heard, did, and the patient response. Avoid personal opinions and subjective language.', area: 'documentation-procedures', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'cc-dp-03', question: 'Which of the following is an example of objective documentation?', options: ['The patient seemed angry', 'Blood pressure 140/90 mmHg', 'The patient appeared to be in pain', 'The family was uncooperative'], correctAnswer: 1, explanation: 'Objective documentation includes measurable, observable findings. "Blood pressure 140/90 mmHg" is a measurable vital sign. The other options are subjective interpretations that should be documented as patient statements or specific behaviors instead.', area: 'documentation-procedures', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'cc-dp-04', question: 'An addendum to a PCR should be:', options: ['Deleted and rewritten', 'Dated, timed, and clearly identified as an addendum', 'Added without any notation', 'Never allowed once the PCR is submitted'], correctAnswer: 1, explanation: 'Addendums are allowed and should be dated, timed, clearly identified as an addendum, and explain why the addition is being made. Never alter the original documentation or delete information.', area: 'documentation-procedures', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'cc-dp-05', question: 'HIPAA compliance in EMS documentation requires:', options: ['Sharing patient information freely with bystanders', 'Protecting patient health information and only sharing with authorized individuals', 'Never documenting any patient information', 'Keeping all records in a public area'], correctAnswer: 1, explanation: 'HIPAA and data privacy laws require that patient health information be protected and only shared with individuals who have a legitimate need to know for treatment, payment, or healthcare operations.', area: 'documentation-procedures', difficulty: 'easy', type: 'multiple-choice' },

  // === CORE COMPETENCIES ===
  // CPR/AED
  { id: 'core-cpr-01', question: 'The correct rate for chest compressions in adult CPR is:', options: ['60-80 per minute', '100-120 per minute', '120-140 per minute', 'As fast as possible'], correctAnswer: 1, explanation: 'The AHA recommends a compression rate of 100-120 per minute for adult CPR. This rate ensures adequate blood flow while allowing for chest recoil between compressions.', area: 'cpr-aed', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'core-cpr-02', question: 'The correct depth for adult chest compressions is:', options: ['1 inch', 'At least 2 inches (5 cm)', '3 inches', 'As deep as possible'], correctAnswer: 1, explanation: 'Adult chest compressions should be at least 2 inches (5 cm) deep. Compressions that are too shallow will not effectively circulate blood, while compressions that are too deep may cause injury.', area: 'cpr-aed', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'core-cpr-03', question: 'When using an AED, the first step after turning on the device is to:', options: ['Press the shock button immediately', 'Apply the pads to the patient bare chest', 'Check for a pulse', 'Start chest compressions'], correctAnswer: 1, explanation: 'After turning on the AED, the next step is to apply the electrode pads to the patient bare chest. The AED will then analyze the rhythm and provide voice prompts for further actions.', area: 'cpr-aed', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'core-cpr-04', question: 'The compression-to-ventilation ratio for single-rescuer adult CPR is:', options: ['15:1', '15:2', '30:1', '30:2'], correctAnswer: 3, explanation: 'The compression-to-ventilation ratio for single-rescuer adult CPR is 30:2 (30 compressions followed by 2 ventilations). For two-rescuer CPR, the ratio is also 30:2 for adults.', area: 'cpr-aed', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'core-cpr-05', question: 'Before using an AED, you should ensure:', options: ['The patient is on a wet surface', 'No one is touching the patient during analysis and shock', 'Oxygen is flowing over the patient chest', 'The patient has been in cardiac arrest for at least 10 minutes'], correctAnswer: 1, explanation: 'Before AED analysis and shock delivery, ensure no one is touching the patient. Also ensure the patient is on a dry surface, remove medication patches from the chest, and move oxygen away from the chest area.', area: 'cpr-aed', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'core-cpr-06', question: 'An AED should NOT be used on a patient who:', options: ['Is unresponsive', 'Is in water with no way to move', 'Has a known do-not-resuscitate order', 'Is breathing normally'], correctAnswer: 3, explanation: 'An AED should not be used on a patient who is breathing normally, as they do not need CPR or defibrillation. AEDs are for patients in cardiac arrest (unresponsive, not breathing normally, no pulse). DNR orders and wet environments require other considerations but are not absolute contraindications.', area: 'cpr-aed', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'core-cpr-07', question: 'If the AED indicates "no shock advised," you should:', options: ['Remove the AED pads', 'Resume CPR immediately', 'Check the battery', 'Wait for the AED to shock automatically'], correctAnswer: 1, explanation: 'If the AED indicates "no shock advised," resume CPR immediately starting with chest compressions. Continue CPR and follow the AED prompts for periodic rhythm checks.', area: 'cpr-aed', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'core-cpr-08', question: 'AED pad placement for an adult should be:', options: ['Both pads on the front of the chest', 'One pad on the upper right chest, one on the lower left side', 'One pad on each arm', 'Both pads on the back'], correctAnswer: 1, explanation: 'Standard AED pad placement for adults: one pad on the upper right chest (below the collarbone) and one pad on the lower left side (below the armpit). This allows the electrical current to pass through the heart.', area: 'cpr-aed', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'core-cpr-09', question: 'For infant CPR, the compression depth should be:', options: ['1/3 the depth of the chest (about 1.5 inches)', '2 inches', '3 inches', 'As deep as possible'], correctAnswer: 0, explanation: 'For infants, compress the chest about 1/3 the depth of the chest, approximately 1.5 inches (4 cm). Use two fingers or the two-thumb encircling hands technique for compressions.', area: 'cpr-aed', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'core-cpr-10', question: 'The most common cause of airway obstruction in an unconscious patient is:', options: ['Foreign body', 'The tongue', 'Swelling', 'Infection'], correctAnswer: 1, explanation: 'The tongue is the most common cause of airway obstruction in unconscious patients. When consciousness is lost, the muscles of the tongue and throat relax, allowing the tongue to fall back and block the airway.', area: 'cpr-aed', difficulty: 'medium', type: 'multiple-choice' },

  // Basic Life Support
  { id: 'core-bls-01', question: 'The CAB sequence in BLS stands for:', options: ['Circulation, Airway, Breathing', 'Compressions, Airway, Breathing', 'Care, Assessment, Breathing', 'Call, Assess, Begin'], correctAnswer: 1, explanation: 'CAB: Compressions, Airway, Breathing. The AHA changed from ABC to CAB in 2010 to emphasize the importance of starting chest compressions immediately for cardiac arrest patients.', area: 'basic-life-support', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'core-bls-02', question: 'The head-tilt/chin-lift maneuver is used to:', options: ['Check for injuries', 'Open the airway of an unconscious patient without suspected spinal injury', 'Perform CPR', 'Assess breathing quality'], correctAnswer: 1, explanation: 'The head-tilt/chin-lift maneuver opens the airway by tilting the head back and lifting the chin. This moves the tongue away from the back of the throat. Do NOT use this technique if spinal injury is suspected.', area: 'basic-life-support', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'core-bls-03', question: 'If a patient has a suspected spinal injury and needs airway management, you should use:', options: ['Head-tilt/chin-lift', 'Jaw-thrust maneuver', 'Blind finger sweep', 'Nasopharyngeal airway only'], correctAnswer: 1, explanation: 'The jaw-thrust maneuver is the preferred technique for opening the airway when spinal injury is suspected. It moves the jaw forward without extending the neck, minimizing spinal movement.', area: 'basic-life-support', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'core-bls-04', question: 'When providing rescue breaths to an adult, each breath should last:', options: ['1 second', '2 seconds', '3 seconds', '5 seconds'], correctAnswer: 0, explanation: 'Each rescue breath should be given over 1 second with just enough volume to produce visible chest rise. Excessive volume or speed can cause gastric distension and compromise ventilation.', area: 'basic-life-support', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'core-bls-05', question: 'The recovery position is used for:', options: ['Cardiac arrest patients', 'Unconscious breathing patients without suspected spinal injury', 'Conscious patients with chest pain', 'Patients with fractures'], correctAnswer: 1, explanation: 'The recovery position (lateral recumbent position) is for unconscious patients who are breathing adequately and have no suspected spinal injury. It maintains the airway and allows fluids to drain from the mouth.', area: 'basic-life-support', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'core-bls-06', question: 'When performing BLS on a pregnant woman in the third trimester, you should:', options: ['Perform CPR normally', 'Tilt the patient 30 degrees to the left during CPR', 'Avoid chest compressions', 'Only perform rescue breaths'], correctAnswer: 1, explanation: 'For pregnant patients in the third trimester, manually displace the uterus to the left or tilt the patient 30 degrees to the left during CPR. This relieves aortocaval compression and improves the effectiveness of chest compressions.', area: 'basic-life-support', difficulty: 'hard', type: 'multiple-choice' },
  { id: 'core-bls-07', question: 'A nasopharyngeal airway (NPA) is contraindicated in patients with:', options: ['Dental problems', 'Suspected basilar skull fracture', 'Consciousness', 'Nausea'], correctAnswer: 1, explanation: 'An NPA is contraindicated in patients with suspected basilar skull fracture, as it could be inserted into the cranial vault through a fractured base of skull. Look for signs like raccoon eyes, Battle sign, or CSF leakage.', area: 'basic-life-support', difficulty: 'hard', type: 'multiple-choice' },
  { id: 'core-bls-08', question: 'The BVM (bag-valve-mask) should deliver approximately:', options: ['200 mL per squeeze', '400-600 mL per squeeze', '1000 mL per squeeze', 'As much as possible'], correctAnswer: 1, explanation: 'A BVM should deliver 400-600 mL per squeeze for an adult. Squeezing the bag too forcefully can cause gastric distension, aspiration, and reduced effectiveness of ventilation.', area: 'basic-life-support', difficulty: 'medium', type: 'multiple-choice' },

  // Ambulance Operations
  { id: 'core-ao-01', question: 'Before starting an ambulance shift, the EMS crew should perform:', options: ['Only a fuel check', 'A comprehensive vehicle and equipment check', 'Only verify the radio works', 'No check is needed if the previous crew confirmed readiness'], correctAnswer: 1, explanation: 'Every shift must begin with a comprehensive vehicle and equipment check, including fuel, fluids, lights, sirens, medical equipment, medications, and supplies. This ensures readiness for emergency response.', area: 'ambulance-operations', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'core-ao-02', question: 'When driving an ambulance with lights and sirens, you should:', options: ['Drive as fast as possible', 'Drive with due regard for safety, following traffic laws with emergency exemptions', 'Ignore all traffic signals', 'Always use the fastest route regardless of conditions'], correctAnswer: 1, explanation: 'Emergency driving requires due regard for safety. While emergency vehicles have certain exemptions, the driver must still operate safely, slow down at intersections, and avoid creating additional hazards.', area: 'ambulance-operations', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'core-ao-03', question: 'The minimum number of people recommended to load a standard stretcher with a patient is:', options: ['1', '2', '3', '4'], correctAnswer: 1, explanation: 'A minimum of 2 people are needed to load a standard stretcher with a patient. Additional personnel may be needed for heavy patients, difficult terrain, or when using a stair chair.', area: 'ambulance-operations', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'core-ao-04', question: 'When parking the ambulance at an emergency scene, you should:', options: ['Park as close to the incident as possible', 'Park at least 50 feet from the scene, considering hazards and escape routes', 'Park on the roadway to block traffic', 'Park anywhere convenient'], correctAnswer: 1, explanation: 'Park at a safe distance (at least 50 feet) from the scene, consider potential hazards, maintain an escape route, and position the ambulance to serve as a barrier if on a roadway. Safety of the crew and vehicle is paramount.', area: 'ambulance-operations', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'core-ao-05', question: 'During ambulance transport, the patient should be secured with:', options: ['Only the stretcher straps', 'Stretcher straps and the stretcher locked in the mounting system', 'Held by hand by a team member', 'Nothing if the ride is smooth'], correctAnswer: 1, explanation: 'Patients must be secured with all stretcher straps AND the stretcher must be locked into the ambulance mounting system. This prevents patient injury during sudden stops or turns.', area: 'ambulance-operations', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'core-ao-06', question: 'The ambulance compartment should be cleaned and disinfected:', options: ['Only when visibly soiled', 'After every patient transport', 'Once a week', 'Only at the end of each shift'], correctAnswer: 1, explanation: 'The ambulance patient compartment should be cleaned and disinfected after every patient transport. This prevents cross-contamination and protects both patients and EMS providers.', area: 'ambulance-operations', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'core-ao-07', question: 'When backing up an ambulance, you should:', options: ['Do it quickly', 'Use a spotter whenever possible', 'Rely only on mirrors', 'Honk the horn repeatedly'], correctAnswer: 1, explanation: 'When backing up an ambulance, use a spotter whenever possible. The spotter should stand at the rear corner on the driver side and use standardized hand signals to guide the driver.', area: 'ambulance-operations', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'core-ao-08', question: 'Code 3 response means:', options: ['Non-emergency response, no lights or sirens', 'Emergency response with lights and sirens', 'Return to base', 'Meal break'], correctAnswer: 1, explanation: 'Code 3 typically means emergency response with lights and sirens. Code 1 is routine/non-emergency, and Code 2 is urgent but without lights and sirens (protocols may vary by agency).', area: 'ambulance-operations', difficulty: 'easy', type: 'multiple-choice' },

  // Emergency Scene Management
  { id: 'core-esm-01', question: 'The first priority upon arriving at an emergency scene is:', options: ['Patient care', 'Scene safety', 'Equipment setup', 'Documentation'], correctAnswer: 1, explanation: 'Scene safety is always the first priority. An unsafe scene puts both the provider and patient at risk. If the scene is not safe, do not enter until it has been secured by appropriate personnel.', area: 'emergency-scene-management', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'core-esm-02', question: 'When establishing a danger zone at an emergency scene, the inner perimeter should be:', options: ['As large as possible', 'Limited to essential personnel only', 'Open to the public', 'The same size as the outer perimeter'], correctAnswer: 1, explanation: 'The inner perimeter (hot zone) should be limited to essential personnel only. This protects the integrity of the scene, reduces contamination risk, and ensures patient and provider safety.', area: 'emergency-scene-management', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'core-esm-03', question: 'Incident command system (ICS) is used to:', options: ['Replace all EMS protocols', 'Manage resources and coordinate response during emergencies', 'Eliminate the need for communication', 'Only manage mass casualty incidents'], correctAnswer: 1, explanation: 'ICS provides a standardized management structure for coordinating resources, personnel, and communication during emergencies of any size. It establishes clear roles and a chain of command.', area: 'emergency-scene-management', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'core-esm-04', question: 'When multiple patients are present at a scene, the EMS provider should first:', options: ['Treat the most severely injured patient', 'Perform a rapid triage to prioritize patients', 'Treat the nearest patient', 'Wait for additional resources'], correctAnswer: 1, explanation: 'When multiple patients are present, perform rapid triage first to categorize patients by severity and prioritize care. The START triage system is commonly used for this purpose.', area: 'emergency-scene-management', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'core-esm-05', question: 'A mechanism of injury (MOI) assessment helps determine:', options: ['The patient identity', 'The potential severity and type of injuries', 'The patient insurance status', 'Whether the patient is lying'], correctAnswer: 1, explanation: 'The MOI assessment helps predict the potential severity and type of injuries based on how the injury occurred. For example, a fall from height suggests possible spinal and internal injuries.', area: 'emergency-scene-management', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'core-esm-06', question: 'Scene size-up includes all of the following EXCEPT:', options: ['Assessing scene safety', 'Determining the number of patients', 'Beginning patient treatment', 'Identifying the mechanism of injury'], correctAnswer: 2, explanation: 'Scene size-up includes assessing safety, determining patient count, identifying MOI/nature of illness, and considering resource needs. Patient treatment begins AFTER scene size-up and safety are confirmed.', area: 'emergency-scene-management', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'core-esm-07', question: 'At a crime scene, EMS providers should:', options: ['Collect evidence for police', 'Provide patient care while being careful not to disturb evidence unnecessarily', 'Delay patient care until police finish investigation', 'Photograph the scene for documentation'], correctAnswer: 1, explanation: 'Patient care always takes priority at a crime scene. However, EMS providers should be careful not to disturb evidence unnecessarily and should document any alterations to the scene.', area: 'emergency-scene-management', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'core-esm-08', question: 'Personal protective equipment at a hazardous materials incident should include:', options: ['Standard EMS PPE only', 'Appropriate level PPE based on the hazardous material', 'No PPE to avoid contamination', 'Only gloves'], correctAnswer: 1, explanation: 'HazMat incidents require PPE appropriate to the specific hazard. Levels A through D provide varying degrees of protection. EMS providers should not enter a HazMat zone without proper equipment and training.', area: 'emergency-scene-management', difficulty: 'hard', type: 'multiple-choice' },

  // Pre-Hospital Care
  { id: 'core-phc-01', question: 'The golden hour in trauma refers to:', options: ['The first hour of a shift', 'The critical first 60 minutes from injury to definitive care', 'The time spent on scene', 'The hour before transport'], correctAnswer: 1, explanation: 'The golden hour refers to the critical first 60 minutes from the time of injury to definitive surgical care. Research shows that patients who receive definitive care within this time frame have significantly better outcomes.', area: 'pre-hospital-care', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'core-phc-02', question: 'The platinum 10 minutes refers to:', options: ['Time spent on scene for a trauma patient', 'The maximum time spent on scene for critical trauma patients', 'Time to administer medication', 'Time to complete documentation'], correctAnswer: 1, explanation: 'The platinum 10 minutes is the recommended maximum on-scene time for critical trauma patients. Minimizing scene time helps get the patient to definitive care within the golden hour.', area: 'pre-hospital-care', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'core-phc-03', question: 'Position of function for a patient in shock without suspected spinal injury is:', options: ['Supine with legs elevated (Trendelenburg position)', 'Sitting upright', 'Prone position', 'Left lateral recumbent'], correctAnswer: 0, explanation: 'For a patient in shock without spinal injury, place them supine with legs elevated approximately 12 inches (modified Trendelenburg position). This helps improve venous return to the heart.', area: 'pre-hospital-care', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'core-phc-04', question: 'When managing a patient with chest pain, the first medication typically administered is:', options: ['Nitroglycerin', 'Aspirin (162-325 mg chewed)', 'Morphine', 'Oxygen at high flow'], correctAnswer: 1, explanation: 'For suspected cardiac chest pain, aspirin (162-325 mg chewed) is typically the first medication given to inhibit platelet aggregation. Nitroglycerin may follow if blood pressure allows and authorized by medical direction.', area: 'pre-hospital-care', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'core-phc-05', question: 'The primary survey should take approximately:', options: ['30 seconds to 1 minute', '5-10 minutes', '15-20 minutes', 'As long as needed'], correctAnswer: 0, explanation: 'The primary survey should take approximately 30 seconds to 1 minute. It is a rapid assessment focused on identifying and treating life-threatening conditions (ABCs). A more detailed assessment follows in the secondary survey.', area: 'pre-hospital-care', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'core-phc-06', question: 'When a patient is in cardiac arrest, the most important intervention is:', options: ['Administering medication', 'High-quality chest compressions', 'Intubation', 'Transport to the hospital'], correctAnswer: 1, explanation: 'High-quality chest compressions are the most important intervention in cardiac arrest. They maintain circulation to vital organs. All other interventions should not significantly interrupt compressions.', area: 'pre-hospital-care', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'core-phc-07', question: 'For a patient experiencing a stroke, time to treatment is critical because:', options: ['Strokes are always fatal', 'Thrombolytic therapy has a limited time window (typically 3-4.5 hours)', 'Strokes resolve on their own', 'Medications are ineffective after 1 hour'], correctAnswer: 1, explanation: 'Thrombolytic (clot-busting) therapy for ischemic stroke must be administered within 3-4.5 hours of symptom onset. Earlier treatment leads to better outcomes. Time is brain.', area: 'pre-hospital-care', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'core-phc-08', question: 'The FAST acronym for stroke assessment stands for:', options: ['First Aid, Assessment, Stabilization, Transport', 'Face drooping, Arm weakness, Speech difficulty, Time to call emergency', 'Flow, Airway, Suction, Treatment', 'Function, Assessment, Status, Treatment'], correctAnswer: 1, explanation: 'FAST: Face drooping (ask the person to smile), Arm weakness (ask to raise both arms), Speech difficulty (ask to repeat a simple phrase), Time to call emergency services immediately if any signs are present.', area: 'pre-hospital-care', difficulty: 'easy', type: 'multiple-choice' },

  // Trauma Management
  { id: 'core-tm-01', question: 'The leading cause of preventable death in trauma is:', options: ['Head injury', 'Hemorrhage (bleeding)', 'Spinal cord injury', 'Fractures'], correctAnswer: 1, explanation: 'Hemorrhage is the leading cause of preventable death in trauma patients. Early recognition and aggressive management of bleeding can save lives. Direct pressure, tourniquets, and hemostatic dressings are key interventions.', area: 'trauma-management', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'core-tm-02', question: 'When controlling severe external bleeding, the first method should be:', options: ['Tourniquet', 'Direct pressure', 'Elevation', 'Pressure points'], correctAnswer: 1, explanation: 'Direct pressure is the first and primary method for controlling external bleeding. Apply firm, direct pressure with a dressing. If bleeding continues, add more dressings and increase pressure. Tourniquets are used when direct pressure fails for extremity hemorrhage.', area: 'trauma-management', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'core-tm-03', question: 'A tourniquet should be applied:', options: ['Over a joint', '2-3 inches above the bleeding site, not over a joint', 'Directly over the wound', 'At the highest point of the limb'], correctAnswer: 1, explanation: 'Apply a tourniquet 2-3 inches above the bleeding site, avoiding placement over joints. Once applied, note the time. A tourniquet should not be removed in the field unless directed by medical control.', area: 'trauma-management', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'core-tm-04', question: 'Signs of internal bleeding include:', options: ['Only visible bruising', 'Tachycardia, hypotension, decreasing mental status, abdominal distension', 'Only pain at the injury site', 'Elevated blood pressure'], correctAnswer: 1, explanation: 'Signs of internal bleeding include tachycardia (early sign), hypotension (late sign), decreasing mental status, abdominal distension and rigidity, pale/cool/clammy skin, and weak pulses.', area: 'trauma-management', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'core-tm-05', question: 'An open chest wound should be managed with:', options: ['A tight bandage that seals the wound completely on all sides', 'An occlusive dressing sealed on three sides (vented chest seal)', 'No dressing - let it breathe', 'A dry gauze pad only'], correctAnswer: 1, explanation: 'An open chest wound (sucking chest wound) should be managed with an occlusive dressing sealed on three sides, creating a flutter valve that allows air to escape but prevents air from entering the chest cavity. This prevents tension pneumothorax.', area: 'trauma-management', difficulty: 'hard', type: 'multiple-choice' },
  { id: 'core-tm-06', question: 'A flail chest is characterized by:', options: ['A single rib fracture', 'Two or more ribs fractured in two or more places, creating a free-floating segment', 'A fractured sternum only', 'Clavicle fracture'], correctAnswer: 1, explanation: 'A flail chest occurs when two or more ribs are fractured in two or more places, creating a free-floating segment that moves paradoxically (inward during inspiration, outward during expiration). This impairs ventilation.', area: 'trauma-management', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'core-tm-07', question: 'The most reliable sign of a fractured bone is:', options: ['Swelling', 'Bruising', 'Deformity', 'Pain'], correctAnswer: 2, explanation: 'While all are signs of fracture, deformity is the most reliable clinical sign of a bone fracture. Other signs include crepitus (grinding sound), loss of function, point tenderness, and swelling.', area: 'trauma-management', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'core-tm-08', question: 'When managing an amputated body part, you should:', options: ['Place it directly on ice', 'Wrap it in sterile dressing, place in a plastic bag, then place the bag on ice', 'Discard it as it cannot be reattached', 'Place it in warm water'], correctAnswer: 1, explanation: 'Wrap the amputated part in sterile moist dressing, place in a sealed plastic bag, then place the bag on ice. Never place the part directly on ice or in water, as this damages tissue and reduces the chance of successful reattachment.', area: 'trauma-management', difficulty: 'medium', type: 'multiple-choice' },

  // Patient Transport
  { id: 'core-pt-01', question: 'The most appropriate device for transporting a patient with suspected spinal injury is:', options: ['Stair chair', 'Long spine board with cervical collar', 'Wheeled stretcher only', 'Scoop stretcher only'], correctAnswer: 1, explanation: 'Patients with suspected spinal injury should be immobilized with a cervical collar and transported on a long spine board or vacuum mattress. Current guidelines emphasize minimizing time on the spine board to prevent complications.', area: 'patient-transport', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'core-pt-02', question: 'When selecting a carrying device, consider all of the following EXCEPT:', options: ['Patient condition', 'Patient weight', 'Distance and terrain', 'Patient preference for color'], correctAnswer: 3, explanation: 'When selecting a carrying device, consider the patient condition, weight, distance to be traveled, terrain, and available personnel. Aesthetic preferences like color are not relevant to patient care decisions.', area: 'patient-transport', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'core-pt-03', question: 'A stair chair is used for:', options: ['Spinal immobilization', 'Moving patients up or down stairs who can sit', 'Lifting heavy patients', 'Water rescue'], correctAnswer: 1, explanation: 'A stair chair is designed for moving patients who can sit upright up or down stairs. It is not for spinal immobilization. Patients who cannot sit or have suspected spinal injuries require different devices.', area: 'patient-transport', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'core-pt-04', question: 'The scoop stretcher is particularly useful for:', options: ['Patients who can walk', 'Patients with suspected hip or spinal injuries who cannot be log-rolled', 'Water rescue', 'Rapid transport only'], correctAnswer: 1, explanation: 'The scoop stretcher splits into two halves that can be placed on either side of the patient and then connected, allowing the patient to be lifted without log-rolling. This is especially useful for hip fractures and certain spinal injuries.', area: 'patient-transport', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'core-pt-05', question: 'When loading a stretcher into an ambulance, the head of the stretcher should go:', options: ['In first (toward the front of the ambulance)', 'In last (toward the rear doors)', 'Sideways', 'It does not matter'], correctAnswer: 0, explanation: 'The head of the stretcher goes in first, toward the front of the ambulance. This allows the patient head to be near the primary care provider seat and equipment, and ensures proper locking of the stretcher.', area: 'patient-transport', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'core-pt-06', question: 'During transport, the EMS provider in the back should:', options: ['Sit without a seatbelt', 'Wear a seatbelt and monitor the patient continuously', 'Stand to provide better access', 'Focus only on documentation'], correctAnswer: 1, explanation: 'The provider in the back should wear a seatbelt whenever possible and continuously monitor the patient. Some care may require unfastening the seatbelt temporarily, but it should be refastened as soon as possible.', area: 'patient-transport', difficulty: 'easy', type: 'multiple-choice' },

  // Emergency Communication
  { id: 'core-ec-01', question: 'When calling medical direction for orders, you should:', options: ['Guess what orders might be needed', 'Provide patient information and assessment findings clearly before requesting orders', 'Demand specific medications', 'Call only as a last resort'], correctAnswer: 1, explanation: 'When contacting medical direction, clearly present patient information and assessment findings before requesting orders. This allows the physician to make informed decisions about patient care.', area: 'emergency-communication', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'core-ec-02', question: 'Radio communication should be:', options: ['Lengthy and detailed', 'Clear, concise, and professional', 'Informal and casual', 'Unnecessary for most calls'], correctAnswer: 1, explanation: 'Radio communication should be clear, concise, and professional. Use standard terminology, avoid unnecessary information, and follow your agency communication protocols.', area: 'emergency-communication', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'core-ec-03', question: 'Patient information transmitted by radio should:', options: ['Include the patient full name', 'Use patient identifiers without names to protect confidentiality', 'Include the patient address', 'Include the patient insurance information'], correctAnswer: 1, explanation: 'Radio communications can be monitored, so protect patient confidentiality by using identifiers rather than names. Refer to "the patient" or use unit/bed numbers instead of names.', area: 'emergency-communication', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'core-ec-04', question: 'The MDT format for radio reports stands for:', options: ['Medical, Diagnostic, Treatment', 'Mechanism, Description, Treatment', 'Medical Direction Telephone', 'It is not a standard EMS radio format'], correctAnswer: 3, explanation: 'MDT is not a standard EMS radio format. Common formats include SBAR, SOAP, and CHART. This question tests critical evaluation of acronyms and misinformation.', area: 'emergency-communication', difficulty: 'hard', type: 'multiple-choice' },
  { id: 'core-ec-05', question: 'When receiving verbal orders from medical direction, you should:', options: ['Execute immediately without repeating', 'Read back the order to confirm accuracy', 'Ignore orders you disagree with', 'Write them down after completing the call'], correctAnswer: 1, explanation: 'Always read back verbal orders to confirm accuracy. This is part of the closed-loop communication process and helps prevent medication errors and treatment mistakes.', area: 'emergency-communication', difficulty: 'easy', type: 'multiple-choice' },

  // Safe Extrication
  { id: 'core-se-01', question: 'The primary goal of patient extrication is:', options: ['Removing the vehicle from around the patient', 'Removing the patient from the vehicle safely while protecting them from further injury', 'Getting the patient out as quickly as possible', 'Dismantling the vehicle completely'], correctAnswer: 1, explanation: 'The primary goal is to safely remove the patient while protecting them from further injury. This may involve creating space in the vehicle rather than simply pulling the patient out. Speed must be balanced with safety.', area: 'safe-extrication', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'core-se-02', question: 'Before beginning vehicle extrication, you must ensure:', options: ['The vehicle is running', 'The vehicle is stable, battery is disconnected, and hazards are controlled', 'The patient is conscious', 'Spectators are recording'], correctAnswer: 1, explanation: 'Before extrication, ensure the vehicle is stable (chocked wheels), the battery is disconnected, airbags are deployed or disabled, and all hazards (fire, fluid leaks, electrical) are controlled.', area: 'safe-extrication', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'core-se-03', question: 'During extrication of a patient with suspected spinal injury, the EMS provider should:', options: ['Pull the patient out quickly', 'Maintain manual in-line stabilization throughout the process', 'Allow the patient to self-extricate', 'Remove the cervical collar to facilitate movement'], correctAnswer: 1, explanation: 'Manual in-line stabilization must be maintained throughout the entire extrication process for patients with suspected spinal injuries. The cervical collar should remain in place. A rapid extrication technique may be used if the scene is unsafe.', area: 'safe-extrication', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'core-se-04', question: 'Rapid extrication is indicated when:', options: ['The patient complains of minor pain', 'The scene is unsafe or the patient condition requires immediate transport', 'The vehicle is stable and safe', 'There are plenty of rescuers available'], correctAnswer: 1, explanation: 'Rapid extrication is indicated when the scene presents an immediate danger (fire, hazardous materials, unstable vehicle) or when the patient condition is so critical that immediate transport is necessary.', area: 'safe-extrication', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'core-se-05', question: 'When a patient is trapped and the vehicle is on fire, the priority is:', options: ['Wait for fire department', 'Remove the patient from immediate danger while maintaining spinal protection as much as possible', 'Extinguish the fire yourself', 'Let the patient self-extricate'], correctAnswer: 1, explanation: 'When fire threatens the patient, immediate removal takes priority, even if it means compromising ideal spinal immobilization. The immediate threat to life from fire outweighs the potential for spinal injury during emergency removal.', area: 'safe-extrication', difficulty: 'hard', type: 'multiple-choice' },

  // Mass Casualty
  { id: 'core-mc-01', question: 'In the START triage system, the color RED indicates:', options: ['Deceased', 'Minor injuries', 'Immediate/life-threatening - treat first', 'Delayed - treat second'], correctAnswer: 2, explanation: 'In START triage: RED = Immediate (life-threatening, requires immediate treatment), YELLOW = Delayed (serious but can wait), GREEN = Minor (walking wounded), BLACK = Deceased/expectant.', area: 'mass-casualty', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'core-mc-02', question: 'The first step in START triage is to:', options: ['Begin treating the most injured patient', 'Ask all patients who can walk to move to a designated area', 'Count all patients', 'Call for helicopters'], correctAnswer: 1, explanation: 'The first step in START triage is to ask all patients who can walk to move to a designated area. These patients are categorized as GREEN (minor) and are assessed last. This quickly identifies the walking wounded and allows focus on more critical patients.', area: 'mass-casualty', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'core-mc-03', question: 'In START triage, a patient who cannot walk, has absent radial pulse, and is not breathing is categorized as:', options: ['RED - Immediate', 'YELLOW - Delayed', 'GREEN - Minor', 'BLACK - Deceased/Expectant'], correctAnswer: 3, explanation: 'In START triage, a patient who is not breathing and has no radial pulse is categorized as BLACK (deceased/expectant). However, if opening the airway causes the patient to breathe, they are reclassified as RED.', area: 'mass-casualty', difficulty: 'hard', type: 'multiple-choice' },
  { id: 'core-mc-04', question: 'The Incident Commander in a mass casualty incident is responsible for:', options: ['Treating the most critical patient', 'Overall management and coordination of the incident', 'Transporting patients', 'Managing media relations only'], correctAnswer: 1, explanation: 'The Incident Commander manages the overall incident, coordinates resources, establishes command, and ensures effective operations. They do not directly treat patients but oversee the entire response.', area: 'mass-casualty', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'core-mc-05', question: 'The primary purpose of triage in a mass casualty incident is to:', options: ['Treat patients in order of arrival', 'Do the greatest good for the greatest number of people', 'Treat only the most severely injured', 'Transport patients to the nearest hospital'], correctAnswer: 1, explanation: 'The purpose of triage is to do the greatest good for the greatest number of people by allocating limited resources to those who will benefit most. This may mean bypassing patients with non-survivable injuries to treat those with survivable ones.', area: 'mass-casualty', difficulty: 'easy', type: 'multiple-choice' },

  // Oxygen Administration
  { id: 'core-oa-01', question: 'A nasal cannula delivers oxygen at a flow rate of:', options: ['1-6 L/min (24-44% O2)', '6-15 L/min', '15-25 L/min', '100% O2 at any flow rate'], correctAnswer: 0, explanation: 'A nasal cannula delivers oxygen at 1-6 L/min, providing approximately 24-44% FiO2. It is used for patients who need low-flow supplemental oxygen and can breathe through their nose.', area: 'oxygen-administration', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'core-oa-02', question: 'A non-rebreather mask can deliver approximately what percentage of oxygen?', options: ['40-60%', '60-80%', '80-95%', '100%'], correctAnswer: 2, explanation: 'A non-rebreather mask at 10-15 L/min can deliver approximately 80-95% oxygen. It is the preferred device for patients who need high-concentration oxygen and are breathing adequately.', area: 'oxygen-administration', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'core-oa-03', question: 'A simple face mask delivers oxygen at a flow rate of:', options: ['1-4 L/min', '6-10 L/min (40-60% O2)', '10-15 L/min', '15-25 L/min'], correctAnswer: 1, explanation: 'A simple face mask delivers oxygen at 6-10 L/min, providing approximately 40-60% FiO2. It should never be used below 6 L/min to prevent rebreathing of exhaled CO2.', area: 'oxygen-administration', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'core-oa-04', question: 'When using a BVM with supplemental oxygen, the flow rate should be:', options: ['1-6 L/min', '10-15 L/min', '25-30 L/min', 'It does not need supplemental oxygen'], correctAnswer: 1, explanation: 'When using a BVM with supplemental oxygen, attach oxygen at 10-15 L/min. This allows the BVM to deliver high concentrations of oxygen with each ventilation.', area: 'oxygen-administration', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'core-oa-05', question: 'Oxygen cylinders should be stored:', options: ['On their side', 'Upright and secured', 'In direct sunlight', 'Near heat sources'], correctAnswer: 1, explanation: 'Oxygen cylinders must be stored upright and secured to prevent falling. Keep them away from heat sources and flammable materials. Always check that cylinders are full and functioning before each shift.', area: 'oxygen-administration', difficulty: 'easy', type: 'multiple-choice' },

  // Spinal Immobilization
  { id: 'core-si-01', question: 'Indications for spinal immobilization include:', options: ['Only patients with obvious paralysis', 'Any patient with mechanism of injury that could cause spinal injury, even without symptoms', 'Only patients who are unconscious', 'Only patients who complain of back pain'], correctAnswer: 1, explanation: 'Spinal immobilization should be considered for any patient with a mechanism of injury that could cause spinal injury, regardless of symptoms. This includes falls from height, motor vehicle crashes, diving injuries, and any significant blunt trauma to the head or neck.', area: 'spinal-immobilization', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'core-si-02', question: 'The correct size cervical collar should:', options: ['Be as large as possible for comfort', 'Allow the chin to fit snugly without allowing flexion or extension', 'Be loose enough to slide a finger underneath easily', 'Cover the entire face'], correctAnswer: 1, explanation: 'A properly sized cervical collar should allow the chin to fit snugly, prevent flexion and extension of the neck, and extend from the chin to the suprasternal notch. Manual in-line stabilization must be maintained until the collar is properly applied.', area: 'spinal-immobilization', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'core-si-03', question: 'Manual in-line stabilization should be maintained:', options: ['Only until the cervical collar is applied', 'Until the patient is fully immobilized on a long spine board', 'For only 5 minutes', 'Only during transport'], correctAnswer: 1, explanation: 'Manual in-line stabilization must be maintained from initial contact until the patient is completely immobilized on the long spine board or vacuum mattress. A cervical collar alone does not provide adequate immobilization.', area: 'spinal-immobilization', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'core-si-04', question: 'The log-roll technique requires a minimum of:', options: ['1 rescuer', '2 rescuers', '3 rescuers (one at head, one at shoulders/hips, one at legs)', '5 rescuers'], correctAnswer: 2, explanation: 'A minimum of 3 rescuers are needed for a log roll: one maintains in-line stabilization at the head, one controls the shoulders and hips, and one controls the legs and torso. The person at the head directs the roll.', area: 'spinal-immobilization', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'core-si-05', question: 'Current evidence-based guidelines suggest that long spine boards should:', options: ['Be used for all trauma patients', 'Be used selectively and patients should be removed as soon as possible', 'Be left on patients for the entire hospital stay', 'Not be used at all'], correctAnswer: 1, explanation: 'Current guidelines recommend selective use of long spine boards and early removal. Prolonged immobilization can cause pressure ulcers, respiratory compromise, and pain. Vacuum mattresses are an increasingly preferred alternative.', area: 'spinal-immobilization', difficulty: 'hard', type: 'multiple-choice' },

  // Splinting and Bandaging
  { id: 'core-sb-01', question: 'The general rule for splinting a fracture is to:', options: ['Splint only if the bone is visible', 'Splint the joint above and the joint below the fracture', 'Splint only the fracture site', 'Apply the splint loosely to avoid pain'], correctAnswer: 1, explanation: 'A splint should immobilize the joint above and the joint below the fracture site. This prevents movement at the fracture and reduces pain and further tissue damage.', area: 'splinting-bandaging', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'core-sb-02', question: 'Before applying a splint, you should:', options: ['Apply it directly over clothing', 'Assess pulse, motor function, and sensation (PMS) distal to the injury', 'Give pain medication only', 'Move the limb to normal alignment'], correctAnswer: 1, explanation: 'Always assess and document pulse, motor function, and sensation (PMS) distal to the injury before AND after applying a splint. This establishes a baseline and ensures the splint is not compromising circulation.', area: 'splinting-bandaging', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'core-sb-03', question: 'A traction splint is used for:', options: ['Upper arm fractures', 'Femur (thigh bone) fractures', 'Ankle fractures', 'Clavicle fractures'], correctAnswer: 1, explanation: 'Traction splints are specifically designed for femur fractures. They apply constant traction to the leg, reducing muscle spasms, decreasing pain, and minimizing blood loss from the fracture site.', area: 'splinting-bandaging', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'core-sb-04', question: 'When applying a pressure dressing for bleeding control:', options: ['Apply it loosely', 'Apply firm, direct pressure and secure it tightly', 'Remove it every 5 minutes to check', 'Apply a tourniquet instead'], correctAnswer: 1, explanation: 'A pressure dressing should be applied firmly over the wound with direct pressure, then secured tightly. Do not remove the dressing to check bleeding. If bleeding soaks through, add more dressing on top and apply additional pressure.', area: 'splinting-bandaging', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'core-sb-05', question: 'An angular bandage (cravat) is typically used for:', options: ['Direct wound coverage', 'Securing splints, slings, and swaths', 'Oxygen delivery', 'Airway management'], correctAnswer: 1, explanation: 'Cravats (triangular bandages folded into strips) are versatile tools used for securing splints, creating arm slings, applying swaths, and holding dressings in place. They are a fundamental component of EMS bandaging supplies.', area: 'splinting-bandaging', difficulty: 'easy', type: 'multiple-choice' },

  // Radio Communication
  { id: 'core-rc-01', question: 'The standard format for an EMS radio report typically includes:', options: ['Only the patient name', 'Unit identification, patient information, assessment findings, treatment, and request', 'Only the destination hospital', 'Just the chief complaint'], correctAnswer: 1, explanation: 'A standard radio report includes: unit identification, patient age/sex, chief complaint, brief history, vital signs, physical exam findings, treatment provided, and any specific requests or needs.', area: 'radio-communication', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'core-rc-02', question: 'When communicating via radio, you should:', options: ['Hold the microphone close and speak loudly', 'Wait for the channel to clear, identify your unit, then speak clearly', 'Interrupt other communications if your call is urgent', 'Use the radio for personal messages between calls'], correctAnswer: 1, explanation: 'Proper radio procedure: wait for the channel to clear, identify your unit, speak clearly at a normal volume with the microphone at an appropriate distance, and keep transmissions brief and professional.', area: 'radio-communication', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'core-rc-03', question: 'The phonetic alphabet is used in radio communication to:', options: ['Sound professional', 'Clearly spell out words and avoid miscommunication', 'Encode confidential information', 'Reduce transmission time'], correctAnswer: 1, explanation: 'The phonetic alphabet (Alpha, Bravo, Charlie, etc.) is used to clearly spell out critical words and avoid miscommunication, especially in noisy environments or when reception is poor.', area: 'radio-communication', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'core-rc-04', question: 'When receiving a radio transmission, you should:', options: ['Ignore it if you are busy', 'Acknowledge receipt and repeat key information', 'Respond with only "copy"', 'Wait 5 minutes before responding'], correctAnswer: 1, explanation: 'Always acknowledge radio transmissions and repeat key information to confirm understanding. This ensures accurate communication and follows the principles of closed-loop communication.', area: 'radio-communication', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'core-rc-05', question: '"10-codes" in EMS radio communication:', options: ['Are universally standardized', 'Are being replaced by plain language communication in many systems', 'Must always be used', 'Are required by law'], correctAnswer: 1, explanation: 'Many EMS systems are moving away from 10-codes toward plain language communication to reduce confusion, especially during multi-agency responses where different codes may mean different things. NIMS/ICS recommends plain language.', area: 'radio-communication', difficulty: 'medium', type: 'multiple-choice' },

  // Emergency Childbirth
  { id: 'core-ecb-01', question: 'The most common presentation in normal childbirth is:', options: ['Breech (feet first)', 'Vertex (head first, face down)', 'Transverse', 'Face first'], correctAnswer: 1, explanation: 'The vertex (cephalic) presentation, with the head first and face pointing downward (occiput anterior), is the most common and normal presentation, occurring in approximately 95% of births.', area: 'emergency-childbirth', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'core-ecb-02', question: 'When the baby head is delivered, you should first:', options: ['Pull the baby out', 'Check for and clear the umbilical cord around the neck', 'Cut the umbilical cord immediately', 'Turn the baby face up'], correctAnswer: 1, explanation: 'After the head is delivered, check if the umbilical cord is wrapped around the neck (nuchal cord). If present, gently slip it over the head. If too tight, clamp and cut the cord. This prevents strangulation during delivery.', area: 'emergency-childbirth', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'core-ecb-03', question: 'The APGAR score is assessed at:', options: ['1 minute and 5 minutes after birth', 'Only at 10 minutes', 'Only at 1 minute', 'Before delivery'], correctAnswer: 0, explanation: 'APGAR scores are assessed at 1 minute and 5 minutes after birth. Each of five categories (Appearance, Pulse, Grimace, Activity, Respiration) is scored 0-2, for a maximum of 10. Scores below 7 require intervention.', area: 'emergency-childbirth', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'core-ecb-04', question: 'In a breech delivery, the greatest danger is:', options: ['Excessive bleeding', 'Head entrapment after the body is delivered', 'Cord prolapse', 'Maternal infection'], correctAnswer: 1, explanation: 'In a breech delivery, the greatest danger is head entrapment. After the body delivers, the head may become trapped because the cervix closes around the narrower body before the larger head can pass through.', area: 'emergency-childbirth', difficulty: 'hard', type: 'multiple-choice' },
  { id: 'core-ecb-05', question: 'After delivery, the placenta should be delivered within:', options: ['5 minutes', '10-30 minutes', '1 hour', '2 hours'], correctAnswer: 1, explanation: 'The placenta typically delivers within 10-30 minutes after birth. Do not pull on the umbilical cord to expedite delivery. Allow the placenta to deliver naturally and save it for hospital inspection.', area: 'emergency-childbirth', difficulty: 'medium', type: 'multiple-choice' },

  // Disaster Response
  { id: 'core-dr-01', question: 'The National Disaster Risk Reduction and Management Council (NDRRMC) in the Philippines uses a color-coded warning system. RED means:', options: ['Low risk', 'Medium risk', 'High risk - emergency', 'All clear'], correctAnswer: 2, explanation: 'In the Philippine warning system: RED indicates high risk/emergency requiring immediate action, YELLOW indicates medium risk/preparation, and GREEN indicates low risk/monitoring.', area: 'disaster-response', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'core-dr-02', question: 'During an earthquake, the recommended action is:', options: ['Run outside immediately', 'Drop, Cover, and Hold On', 'Stand in a doorway', 'Get in an elevator'], correctAnswer: 1, explanation: 'Drop to the ground, take Cover under a sturdy table or desk, and Hold On until the shaking stops. This protects you from falling objects. Do not run outside during shaking as debris may fall.', area: 'disaster-response', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'core-dr-03', question: 'The role of EMS during a disaster includes:', options: ['Managing the entire disaster response', 'Providing medical care, triage, and transport within the incident command structure', 'Only transporting the deceased', 'Only providing first aid at shelters'], correctAnswer: 1, explanation: 'EMS role in disasters includes providing medical care, performing triage, transporting patients, and operating within the Incident Command System. EMS is one component of a coordinated multi-agency disaster response.', area: 'disaster-response', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'core-dr-04', question: 'During a flood, EMS operations should:', options: ['Drive through flooded roads', 'Never attempt to drive or walk through floodwaters', 'Only respond to calls on high ground', 'Use boats for all transports'], correctAnswer: 1, explanation: 'Never attempt to drive or walk through floodwaters. Six inches of moving water can knock you down, and one foot can carry away a vehicle. "Turn around, don\'t drown" is the key safety message.', area: 'disaster-response', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'core-dr-05', question: 'After a disaster, the EMS provider should be aware of:', options: ['Only immediate physical injuries', 'Structural hazards, contamination, infectious disease risk, and psychological impact', 'Only traffic conditions', 'Only the number of casualties'], correctAnswer: 1, explanation: 'After disasters, EMS providers must be aware of multiple hazards: structural instability, hazardous materials contamination, infectious disease risk from contaminated water and debris, and the psychological impact on victims and providers.', area: 'disaster-response', difficulty: 'medium', type: 'multiple-choice' },

  // Triage System
  { id: 'core-ts-01', question: 'The START triage system stands for:', options: ['Simple Triage and Rapid Treatment', 'Standard Triage and Rescue Technique', 'Systematic Treatment and Rapid Transport', 'Safe Triage and Response Team'], correctAnswer: 0, explanation: 'START stands for Simple Triage and Rapid Treatment. It is a rapid assessment system that categorizes patients into four groups: Immediate (Red), Delayed (Yellow), Minor (Green), and Expectant/Deceased (Black).', area: 'triage-system', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'core-ts-02', question: 'In the RPM method of START triage, RPM stands for:', options: ['Respirations, Perfusion, Mental status', 'Rapid, Patient, Management', 'Rescue, Protect, Move', 'Response, Pulse, Movement'], correctAnswer: 0, explanation: 'RPM: Respirations (over 30/min = RED), Perfusion (absent radial pulse or capillary refill over 2 seconds = RED), Mental status (unable to follow commands = RED). This provides a quick, systematic assessment.', area: 'triage-system', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'core-ts-03', question: 'A patient with a respiratory rate of 36, no radial pulse, and unable to follow commands would be triaged as:', options: ['GREEN', 'YELLOW', 'RED', 'BLACK'], correctAnswer: 2, explanation: 'This patient has multiple RED criteria: respirations over 30/min, absent radial pulse, and unable to follow commands. Any one of these would place the patient in the RED (Immediate) category.', area: 'triage-system', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'core-ts-04', question: 'In jumpSTART pediatric triage, children who can walk are categorized as:', options: ['RED', 'YELLOW', 'GREEN', 'BLACK'], correctAnswer: 2, explanation: 'Similar to START triage for adults, in jumpSTART pediatric triage, children who can walk are categorized as GREEN (Minor). This is the first step in the triage process to quickly identify the least injured patients.', area: 'triage-system', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'core-ts-05', question: 'Triage tags should be placed on the patient:', options: ['In their pocket', 'Around the neck or attached to the body in a visible location', 'Given to a family member', 'Placed on the stretcher only'], correctAnswer: 1, explanation: 'Triage tags should be placed around the neck or attached to the body in a clearly visible location. They must remain with the patient throughout the incident and transport to ensure consistent tracking and prioritization.', area: 'triage-system', difficulty: 'easy', type: 'multiple-choice' },

  // Ambulance Driving
  { id: 'core-ad-01', question: 'When approaching an intersection with a red light while driving Code 3, you should:', options: ['Proceed through without stopping', 'Slow down, ensure all lanes are clear, establish eye contact with other drivers, then proceed', 'Honk the horn continuously and drive through', 'Turn off sirens to avoid attention'], correctAnswer: 1, explanation: 'When approaching a red light or stop sign during Code 3 response, slow down, ensure all lanes are clear, make eye contact with other drivers, and proceed only when it is safe. This is required by most emergency vehicle operation policies.', area: 'ambulance-driving', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'core-ad-02', question: 'The "cushion of safety" concept in emergency driving refers to:', options: ['Driving with a pillow', 'Maintaining adequate following distance and clear escape routes', 'Driving in the center lane only', 'Having a co-driver always'], correctAnswer: 1, explanation: 'The cushion of safety involves maintaining adequate following distance (4-6 seconds), keeping escape routes open (avoiding being boxed in), and constantly scanning for potential hazards while driving.', area: 'ambulance-driving', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'core-ad-03', question: 'When transporting a critical patient, the driver should:', options: ['Drive as fast as possible regardless of conditions', 'Drive smoothly, avoiding sudden starts, stops, and turns', 'Take the shortest route even if it has many turns', 'Ignore traffic signals'], correctAnswer: 1, explanation: 'Smooth driving is critical during patient transport. Sudden movements can dislodge equipment, cause additional injury, and interfere with patient care in the back. Drive with due regard while maintaining smooth, predictable movements.', area: 'ambulance-driving', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'core-ad-04', question: 'The most common type of ambulance collision is:', options: ['Head-on collision', 'Intersection collision', 'Rollover', 'Backing collision'], correctAnswer: 1, explanation: 'Intersection collisions are the most common type of ambulance crash. This is why slowing down and ensuring all lanes are clear at intersections is critical, even during emergency response.', area: 'ambulance-driving', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'core-ad-05', question: 'When driving in adverse weather conditions, the EMS driver should:', options: ['Maintain normal speed with lights and sirens', 'Reduce speed and increase following distance', 'Pull over and wait for weather to clear', 'Drive on the shoulder of the road'], correctAnswer: 1, explanation: 'In adverse weather (rain, fog, etc.), reduce speed and increase following distance. Lights and sirens do not improve traction or visibility. Safe arrival is always more important than fast arrival.', area: 'ambulance-driving', difficulty: 'easy', type: 'multiple-choice' },

  // Emergency Equipment
  { id: 'core-ee-01', question: 'The Star of Life emblem has how many points?', options: ['5', '6', '7', '8'], correctAnswer: 1, explanation: 'The Star of Life has 6 points, each representing a function of EMS: Detection, Reporting, Response, On-scene care, Care in transit, and Transfer to definitive care. The staff of Asclepius (snake on a staff) is in the center.', area: 'emergency-equipment', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'core-ee-02', question: 'A suction unit should be tested:', options: ['Monthly', 'At the beginning of each shift', 'Only when needed', 'Yearly'], correctAnswer: 1, explanation: 'The suction unit should be tested at the beginning of each shift to ensure it is functioning properly. Check that it generates adequate vacuum, the tubing is intact, and the collection container is empty.', area: 'emergency-equipment', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'core-ee-03', question: 'The Glucometer is used to measure:', options: ['Blood oxygen level', 'Blood glucose (sugar) level', 'Blood pressure', 'Heart rate'], correctAnswer: 1, explanation: 'A glucometer measures blood glucose levels using a small blood sample, typically from a fingerstick. Normal blood glucose is 70-110 mg/dL. Low glucose (hypoglycemia) is a common medical emergency that EMS providers must recognize and treat.', area: 'emergency-equipment', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'core-ee-04', question: 'When checking the ambulance oxygen supply, you should verify:', options: ['Only that the tank is present', 'The pressure gauge reading and that the tank is turned on', 'The color of the tank', 'The manufacturer label only'], correctAnswer: 1, explanation: 'Check the pressure gauge to ensure the tank has adequate oxygen (full tank reads approximately 2000 psi). Also verify the tank is turned on and the regulator is functioning properly.', area: 'emergency-equipment', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'core-ee-05', question: 'A pulse oximeter measures:', options: ['Blood pressure', 'Oxygen saturation in the blood (SpO2) and pulse rate', 'Blood glucose', 'Respiratory rate'], correctAnswer: 1, explanation: 'A pulse oximeter non-invasively measures oxygen saturation (SpO2) in the blood and pulse rate. It works by shining light through the finger and detecting the absorption characteristics of oxygenated and deoxygenated hemoglobin.', area: 'emergency-equipment', difficulty: 'easy', type: 'multiple-choice' },

  // Additional mixed questions for depth
  { id: 'core-mix-01', question: 'Anaphylaxis is best treated initially with:', options: ['Antihistamines alone', 'Epinephrine (adrenaline) via auto-injector', 'Corticosteroids', 'Oxygen only'], correctAnswer: 1, explanation: 'Epinephrine is the first-line treatment for anaphylaxis. It reverses airway constriction, improves blood pressure, and counteracts the allergic response. Auto-injectors (e.g., EpiPen) are commonly used in the field.', area: 'pre-hospital-care', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'core-mix-02', question: 'Signs of a tension pneumothorax include:', options: ['Bilateral equal breath sounds', 'Absent breath sounds on one side, tracheal deviation, hypotension, JVD', 'Improved breathing with positioning', 'Normal vital signs'], correctAnswer: 1, explanation: 'Tension pneumothorax signs include absent/decreased breath sounds on the affected side, tracheal deviation away from the affected side, hypotension, jugular vein distension (JVD), and hyperresonance on percussion.', area: 'trauma-management', difficulty: 'hard', type: 'multiple-choice' },
  { id: 'core-mix-03', question: 'A diabetic patient who is conscious but confused with low blood sugar should be given:', options: ['Insulin', 'Oral glucose or sugar', 'Water only', 'Nothing by mouth'], correctAnswer: 1, explanation: 'A conscious patient with hypoglycemia (low blood sugar) should be given oral glucose or sugary substances. If the patient cannot swallow safely, glucagon or IV dextrose may be needed per protocol.', area: 'pre-hospital-care', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'core-mix-04', question: 'The correct position for a patient with a nosebleed (epistaxis) is:', options: ['Tilt head backward', 'Sit upright with head tilted slightly forward', 'Lie flat on back', 'Tilt head to the side'], correctAnswer: 1, explanation: 'For epistaxis, the patient should sit upright with the head tilted slightly FORWARD. Pinch the soft part of the nostrils. Tilting backward allows blood to drain into the airway and stomach, causing nausea and aspiration risk.', area: 'pre-hospital-care', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'core-mix-05', question: 'When managing a seizure patient, you should:', options: ['Restrain the patient', 'Place something in the mouth to prevent tongue biting', 'Protect the patient from injury, clear the area, and do NOT restrain', 'Hold the patient down firmly'], correctAnswer: 2, explanation: 'During a seizure, protect the patient from injury by clearing the area of dangerous objects. NEVER restrain the patient or place objects in the mouth. After the seizure, place the patient in the recovery position and monitor airway and breathing.', area: 'pre-hospital-care', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'core-mix-06', question: 'Burns involving the epidermis and part of the dermis, with blisters, are classified as:', options: ['First degree (superficial)', 'Second degree (partial thickness)', 'Third degree (full thickness)', 'Fourth degree'], correctAnswer: 1, explanation: 'Second-degree (partial thickness) burns involve the epidermis and part of the dermis. They present with blisters, redness, swelling, and significant pain due to nerve exposure.', area: 'trauma-management', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'core-mix-07', question: 'The rule of nines is used to estimate:', options: ['Blood loss', 'Body surface area burned', 'Fracture severity', 'Pain level'], correctAnswer: 1, explanation: 'The rule of nines estimates the percentage of body surface area (BSA) affected by burns. In adults: head = 9%, each arm = 9%, anterior trunk = 18%, posterior trunk = 18%, each leg = 18%, perineum = 1%.', area: 'trauma-management', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'core-mix-08', question: 'A patient who is breathing at 8 breaths per minute is exhibiting:', options: ['Normal breathing', 'Bradypnea (abnormally slow breathing)', 'Tachypnea', 'Apnea'], correctAnswer: 1, explanation: 'Bradypnea is abnormally slow breathing, defined as a respiratory rate below 12 breaths per minute in adults. A rate of 8 indicates inadequate ventilation and may require assisted ventilation.', area: 'vital-signs', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'core-mix-09', question: 'In the Philippines, the emergency hotline number is:', questionFil: 'Sa Pilipinas, ang emergency hotline number ay:', options: ['911', '117', 'Both 911 and 922 are used in different areas', '112'], correctAnswer: 0, explanation: 'The Philippines transitioned to using 911 as the national emergency hotline number (previously 117). However, local emergency numbers may vary by area.', area: 'emergency-communication', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'core-mix-10', question: 'When a patient has a suspected abdominal evisceration, you should:', options: ['Push the organs back in', 'Cover with a moist sterile dressing, then a dry dressing, and treat for shock', 'Apply direct pressure', 'Apply a tourniquet'], correctAnswer: 1, explanation: 'For evisceration (organs protruding from the abdomen), do NOT push organs back in. Cover with a moist sterile dressing, then a dry dressing, keep the patient still, and treat for shock. Position the patient supine with knees slightly flexed if possible.', area: 'trauma-management', difficulty: 'hard', type: 'multiple-choice' },

  // ========================================
  // NEW QUESTIONS ADDED - 80+ ADDITIONS
  // ========================================

  // === CORE: CPR with AED - Additional Questions ===
  { id: 'core-cpr-11', question: 'You arrive at a scene where an AED is already attached to a patient in cardiac arrest. The AED advises "Check Electrodes." What is the most likely cause?', options: ['The patient has a shockable rhythm', 'The pads are not making good contact with the skin or are disconnected', 'The battery is low', 'The AED is analyzing correctly'], correctAnswer: 1, explanation: 'A "Check Electrodes" message typically means the AED cannot detect a good connection between the pads and the skin. Check that pads are firmly adhered, cables are connected, and the chest is dry and free of medication patches. Poor contact prevents accurate rhythm analysis.', area: 'cpr-aed', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'core-cpr-12', question: 'When using an AED on a child between 1 and 8 years old, you should:', options: ['Use adult pads placed in the adult position only', 'Use pediatric pads if available; if not, use adult pads with anterior-posterior placement', 'Never use an AED on a child', 'Use only one pad'], correctAnswer: 1, explanation: 'For children 1-8 years, use pediatric AED pads/key if available. If only adult pads are available, use them but place one on the front (center of chest) and one on the back (between shoulder blades) to prevent the pads from touching or overlapping on a small chest.', area: 'cpr-aed', difficulty: 'hard', type: 'multiple-choice' },
  { id: 'core-cpr-13', question: 'A patient with an implanted pacemaker goes into cardiac arrest. When applying AED pads, you should:', options: ['Place the pad directly over the pacemaker device', 'Place the pads at least 1 inch (2.5 cm) away from the pacemaker device', 'Not use the AED at all', 'Place both pads on the back'], correctAnswer: 1, explanation: 'When a patient has an implanted pacemaker or defibrillator (visible as a lump under the skin, usually upper chest), place AED pads at least 1 inch away from the device. The device can block the shock from reaching the heart if pads are placed directly over it.', area: 'cpr-aed', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'core-cpr-14', question: 'During two-rescuer CPR on an adult, the compressor should rotate positions with the ventilator every:', options: ['1 minute', '2 minutes (5 cycles of 30:2)', '5 minutes', '10 minutes'], correctAnswer: 1, explanation: 'In two-rescuer CPR, switch positions every 2 minutes (5 cycles of 30:2 compressions to ventilations) to prevent compressor fatigue and maintain high-quality compressions. The switch should take less than 5 seconds to minimize interruptions.', area: 'cpr-aed', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'core-cpr-15', question: 'The AED analyzes the rhythm and advises a shock. After the shock is delivered, the next action should be:', options: ['Check for a pulse immediately', 'Resume CPR immediately starting with chest compressions', 'Remove the AED pads', 'Wait 30 seconds before doing anything'], correctAnswer: 1, explanation: 'After a shock is delivered, immediately resume CPR starting with chest compressions. Do not check for a pulse first. The AHA guidelines recommend 2 minutes of CPR after each shock before re-analyzing the rhythm. Early CPR after defibrillation increases the chance of ROSC.', area: 'cpr-aed', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'core-cpr-16', question: 'A patient in cardiac arrest has a medication patch on the chest where the AED pad needs to go. You should:', options: ['Place the AED pad directly over the medication patch', 'Remove the patch, wipe the area dry, then apply the AED pad', 'Skip using the AED', 'Place the pad on the opposite side of the chest only'], correctAnswer: 1, explanation: 'Medication patches (e.g., nitroglycerin) on the chest must be removed before applying AED pads. The patch can prevent proper pad adhesion and may cause arcing (sparking) during shock delivery. Remove the patch, wipe the area clean and dry, then apply the AED pad.', area: 'cpr-aed', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'core-cpr-17', question: 'For infant CPR with two rescuers, the compression-to-ventilation ratio should be:', options: ['30:2', '15:2', '15:1', '30:1'], correctAnswer: 1, explanation: 'For two-rescuer infant CPR, the compression-to-ventilation ratio is 15:2. This differs from single-rescuer CPR (30:2 for all ages). The 15:2 ratio provides more frequent ventilations appropriate for pediatric patients. Use the two-thumb encircling hands technique for best results.', area: 'cpr-aed', difficulty: 'hard', type: 'multiple-choice' },
  { id: 'core-cpr-18', question: 'You are performing CPR on a patient who has a return of spontaneous circulation (ROSC). What should you do next?', options: ['Stop all monitoring and prepare for transport', 'Continue to monitor the patient closely, provide supportive care, and prepare for transport', 'Immediately resume chest compressions as a precaution', 'Remove the AED pads'], correctAnswer: 1, explanation: 'After ROSC, closely monitor the patient including vital signs, oxygen saturation, and level of consciousness. Provide supplemental oxygen, assist with ventilation if needed, and prepare for rapid transport. Do not resume compressions unless the patient loses the pulse again.', area: 'cpr-aed', difficulty: 'medium', type: 'multiple-choice' },

  // === CORE: Basic Life Support - Additional Questions ===
  { id: 'core-bls-09', question: 'When ventilating a patient with a BVM, you observe the stomach becoming distended. This is most likely caused by:', options: ['Proper technique', 'Excessive volume or rate of ventilation causing air to enter the stomach', 'The patient swallowing air', 'Normal gastric expansion during CPR'], correctAnswer: 1, explanation: 'Gastric distension during BVM ventilation is caused by delivering too much volume, too much pressure, or too rapid ventilation. Air follows the path of least resistance and enters the stomach. This increases the risk of vomiting and aspiration. Use gentle, slow squeezes and consider using cricoid pressure (Sellick maneuver) if trained.', area: 'basic-life-support', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'core-bls-10', question: 'A conscious adult patient is choking but can still cough forcefully. You should:', options: ['Perform abdominal thrusts immediately', 'Encourage the patient to keep coughing and monitor them closely', 'Perform back blows', 'Attempt blind finger sweeps'], correctAnswer: 1, explanation: 'If a choking patient can cough forcefully, the airway is partially obstructed and they are moving air. Encourage continued coughing and monitor closely. Do not interfere with their efforts. Only intervene with abdominal thrusts if the obstruction becomes severe (inability to cough, speak, or breathe).', area: 'basic-life-support', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'core-bls-11', question: 'When performing abdominal thrusts (Heimlich maneuver) on a conscious choking adult, your hands should be positioned:', options: ['Over the lower ribs', 'Above the navel and below the ribcage (xiphoid process)', 'On the upper chest', 'On the sides of the abdomen'], correctAnswer: 1, explanation: 'Position your hands above the navel and well below the xiphoid process (breastbone). Make a fist with one hand, place the thumb side against the abdomen, grasp with the other hand, and deliver quick upward thrusts. Improper hand placement can cause rib or organ damage.', area: 'basic-life-support', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'core-bls-12', question: 'An oropharyngeal airway (OPA) is measured by:', options: ['Matching the diameter to the patient little finger', 'Measuring from the corner of the mouth to the earlobe or angle of the jaw', 'Estimating based on patient weight', 'Measuring from the chin to the sternum'], correctAnswer: 1, explanation: 'The OPA is sized by measuring from the corner of the mouth to the earlobe or angle of the jaw. An improperly sized OPA can push the tongue back (too small) or cause trauma/laryngospasm (too large). The OPA is contraindicated in conscious patients as it may trigger gagging and vomiting.', area: 'basic-life-support', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'core-bls-13', question: 'A nasopharyngeal airway (NPA) is generally preferred over an OPA when:', options: ['The patient is conscious or has a gag reflex', 'The patient has a basilar skull fracture', 'The patient is a child under 1 year', 'The patient has nasal trauma'], correctAnswer: 0, explanation: 'The NPA is better tolerated in patients who are conscious or semi-conscious with intact gag reflexes, as it is less likely to trigger vomiting. However, it is contraindicated in suspected basilar skull fracture (look for raccoon eyes, Battle sign, CSF from nose/ears) and significant nasal trauma.', area: 'basic-life-support', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'core-bls-14', question: 'During rescue breathing for an adult patient with a pulse but no breathing, you should deliver ventilations at a rate of:', options: ['1 breath every 3 seconds (20 per minute)', '1 breath every 5-6 seconds (10-12 per minute)', '1 breath every 10 seconds (6 per minute)', '1 breath every 15 seconds (4 per minute)'], correctAnswer: 1, explanation: 'For an adult with a pulse but no breathing (respiratory arrest), deliver 1 breath every 5-6 seconds (10-12 breaths per minute). Each breath should be given over 1 second with visible chest rise. Recheck the pulse every 2 minutes.', area: 'basic-life-support', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'core-bls-15', question: 'When performing the jaw-thrust maneuver on a patient with suspected spinal injury, you should:', options: ['Tilt the head back while lifting the jaw', 'Place fingers behind the angle of the jaw and lift forward without moving the head or neck', 'Push down on the forehead while lifting the chin', 'Use one hand to pull the jaw downward'], correctAnswer: 1, explanation: 'The jaw-thrust maneuver involves placing your fingers behind the angles of the mandible (jaw) and lifting the jaw forward while keeping the head and neck in a neutral position. This opens the airway without extending the neck, making it the preferred technique for patients with suspected spinal injury.', area: 'basic-life-support', difficulty: 'medium', type: 'multiple-choice' },

  // === CORE: Ambulance Operations - Additional Questions ===
  { id: 'core-ao-09', question: 'When performing a daily vehicle check, which fluid level should be checked in the ambulance engine?', options: ['Only the fuel level', 'Engine oil, coolant, brake fluid, power steering fluid, and fuel', 'Windshield washer fluid only', 'Transmission fluid only'], correctAnswer: 1, explanation: 'A comprehensive daily vehicle check includes all essential fluids: engine oil, coolant/antifreeze, brake fluid, power steering fluid, transmission fluid, and fuel level. Low fluid levels can lead to mechanical failure during emergency response, endangering the crew and patient.', area: 'ambulance-operations', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'core-ao-10', question: 'When approaching an intersection with a red light while driving Code 3 (lights and sirens), you should:', options: ['Proceed through without slowing down', 'Come to a complete stop, verify the intersection is clear, then proceed with caution', 'Only slow down if you see other vehicles', 'Honk the horn and drive through'], correctAnswer: 1, explanation: 'When approaching a red light or stop sign during Code 3 response, come to a complete stop, ensure all lanes are clear, make eye contact with other drivers when possible, then proceed with caution. Most ambulance crashes occur at intersections. Due regard for safety is always required.', area: 'ambulance-operations', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'core-ao-11', question: 'After transporting a patient with a known infectious disease, the ambulance should be decontaminated using:', options: ['Plain water only', 'An EPA-registered disinfectant appropriate for the suspected pathogen', 'Soap only', 'Alcohol wipes on visible surfaces only'], correctAnswer: 1, explanation: 'Use an EPA-registered hospital-grade disinfectant appropriate for the suspected or confirmed pathogen. Clean all surfaces the patient or body fluids may have contacted. Follow the disinfectant contact time requirements. Plain water and soap alone are insufficient for pathogen elimination.', area: 'ambulance-operations', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'core-ao-12', question: 'When conducting an equipment inventory check at the start of a shift, you discover a critical piece of equipment is missing. You should:', options: ['Continue the shift and note it later', 'Report it immediately and ensure a replacement is obtained before responding to calls', 'Borrow from another unit only when needed', 'Skip that item for the shift'], correctAnswer: 1, explanation: 'Missing critical equipment must be reported and replaced immediately before responding to any calls. Operating without essential equipment puts patients at risk and may violate protocols. Every shift must begin with a complete inventory, and deficiencies must be corrected proactively.', area: 'ambulance-operations', difficulty: 'easy', type: 'multiple-choice' },

  // === CORE: Emergency Scene Management - Additional Questions ===
  { id: 'core-esm-09', question: 'In the Incident Command System (ICS), the Operations Section Chief is responsible for:', options: ['Managing media relations', 'Directing all tactical operations and managing the incident action plan', 'Managing logistics and supplies', 'Handling financial record-keeping'], correctAnswer: 1, explanation: 'The Operations Section Chief directs all tactical field operations and implements the incident action plan. They manage the resources actually performing the work on scene. This role reports directly to the Incident Commander and coordinates with other section chiefs.', area: 'emergency-scene-management', difficulty: 'hard', type: 'multiple-choice' },
  { id: 'core-esm-10', question: 'You arrive at a scene where a chemical tanker has overturned. You notice a strong odor and several people are down. Your first action should be:', options: ['Rush in to help the victims', 'Stage at a safe distance uphill and upwind, and request HazMat response', 'Approach and assess the chemical placards', 'Begin triage immediately'], correctAnswer: 1, explanation: 'Never enter a HazMat scene without proper training and PPE. Stage uphill and upwind at a safe distance, request HazMat resources, and deny entry to the hot zone. Rescuer safety always comes first. The "rule of thumb" is if you can cover the scene with your thumb at arm\'s length, you\'re too close.', area: 'emergency-scene-management', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'core-esm-11', question: 'When managing crowd control at an emergency scene, EMS providers should:', options: ['Physically push bystanders back', 'Establish clear perimeters and rely on law enforcement for crowd management', 'Ignore bystanders entirely', 'Argue with uncooperative bystanders'], correctAnswer: 1, explanation: 'EMS providers should establish clear perimeters using barrier tape or natural boundaries, but should rely on law enforcement for crowd management. EMS should not engage in physical confrontation with bystanders. Focus on patient care and let law enforcement handle access control.', area: 'emergency-scene-management', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'core-esm-12', question: 'At a multiple-patient incident, the "triage officer" role is to:', options: ['Treat the most seriously injured patients', 'Rapidly assess and categorize all patients by severity without providing treatment', 'Transport patients to the hospital', 'Command the entire incident'], correctAnswer: 1, explanation: 'The triage officer rapidly assesses and categorizes patients using a system like START, applying color-coded tags (RED/YELLOW/GREEN/BLACK) without stopping to provide treatment. Treatment begins only after triage is complete. This ensures the greatest good for the greatest number of patients.', area: 'emergency-scene-management', difficulty: 'medium', type: 'multiple-choice' },

  // === CORE: Pre-Hospital Care - Additional Questions ===
  { id: 'core-phc-09', question: 'A patient in hypovolemic shock presents with a blood pressure of 80/50 mmHg, heart rate of 130 bpm, and pale, cool, clammy skin. The most appropriate position for this patient during transport is:', options: ['Sitting upright at 90 degrees', 'Supine with legs elevated approximately 12 inches', 'Prone position', 'Left lateral recumbent position'], correctAnswer: 1, explanation: 'For hypovolemic shock without spinal injury, place the patient supine with legs elevated approximately 12 inches (modified Trendelenburg position). This promotes venous return from the lower extremities and helps maintain blood pressure and perfusion to vital organs.', area: 'pre-hospital-care', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'core-phc-10', question: 'A patient with suspected acute coronary syndrome has a blood pressure of 90/60 mmHg. Regarding nitroglycerin administration, you should:', options: ['Administer nitroglycerin immediately', 'Do NOT administer nitroglycerin; contact medical direction', 'Administer a double dose to compensate for low BP', 'Administer only if the patient insists'], correctAnswer: 1, explanation: 'Nitroglycerin is a vasodilator that lowers blood pressure. It should NOT be administered if the systolic blood pressure is below 90-100 mmHg. In this case with BP 90/60, nitroglycerin could cause dangerous hypotension. Contact medical direction for alternative treatment options.', area: 'pre-hospital-care', difficulty: 'hard', type: 'multiple-choice' },
  { id: 'core-phc-11', question: 'A conscious patient with a suspected spinal injury should be positioned:', options: ['In the recovery position', 'Supine on a long spine board with cervical spine immobilization', 'Sitting upright', 'In a prone position'], correctAnswer: 1, explanation: 'A conscious patient with suspected spinal injury should be maintained in a supine position with cervical spine immobilization using a cervical collar and manual in-line stabilization until fully immobilized on a long spine board or vacuum mattress. Current guidelines emphasize minimizing time on the board.', area: 'pre-hospital-care', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'core-phc-12', question: 'You are assisting a patient with their prescribed bronchodilator inhaler (e.g., albuterol). After the patient takes one puff, you should:', options: ['Have them exhale immediately into the air', 'Have them hold their breath for about 10 seconds if possible, then wait 1-2 minutes before the second puff', 'Administer a second puff immediately', 'Have them lie flat'], correctAnswer: 1, explanation: 'After inhaling a bronchodilator, the patient should hold their breath for about 10 seconds to allow the medication to reach deep into the lungs, then wait 1-2 minutes before taking a second puff. This maximizes medication effectiveness. The patient should use a spacer device if available.', area: 'pre-hospital-care', difficulty: 'medium', type: 'multiple-choice' },

  // === CORE: Trauma Management - Additional Questions ===
  { id: 'core-tm-09', question: 'Using the Rule of Nines, what percentage of body surface area is affected in an adult with full-thickness burns to the entire anterior trunk and both anterior arms?', options: ['18%', '27%', '36%', '45%'], correctAnswer: 1, explanation: 'The Rule of Nines for adults: anterior trunk = 18%, each entire arm = 9%. Both anterior arms = 2 × 9% = 18%, but only the anterior (front) portion of each arm is roughly 4.5%, so both anterior arms = 9%. Total = 18% (anterior trunk) + 9% (both anterior arms) = 27%.', area: 'trauma-management', difficulty: 'hard', type: 'multiple-choice' },
  { id: 'core-tm-10', question: 'A patient presents with absent breath sounds on the right side, tracheal deviation to the left, distended neck veins, and hypotension. These findings indicate:', options: ['Simple pneumothorax', 'Tension pneumothorax', 'Hemothorax', 'Flail chest'], correctAnswer: 1, explanation: 'These are classic signs of a tension pneumothorax: absent breath sounds on the affected side, tracheal deviation AWAY from the affected side, jugular vein distension (JVD), and hypotension. This is a life-threatening emergency requiring needle decompression. Air accumulates under pressure, collapsing the lung and shifting the mediastinum.', area: 'trauma-management', difficulty: 'hard', type: 'multiple-choice' },
  { id: 'core-tm-11', question: 'A patient has a flail chest with paradoxical chest wall movement. The priority management for this patient is:', options: ['Apply a rigid splint to the chest wall', 'Provide positive pressure ventilation and high-flow oxygen', 'Apply a tight bandage around the chest', 'Position the patient prone'], correctAnswer: 1, explanation: 'Flail chest management focuses on providing adequate oxygenation and ventilation. Positive pressure ventilation (BVM with high-flow oxygen) is the most effective treatment as it stabilizes the chest internally and ensures adequate gas exchange. The underlying pulmonary contusion is often the real threat, not the flail segment itself.', area: 'trauma-management', difficulty: 'hard', type: 'multiple-choice' },
  { id: 'core-tm-12', question: 'When applying a tourniquet to control life-threatening extremity hemorrhage, you should document:', options: ['Only the location of the wound', 'The time of tourniquet application, location on the limb, and the reason for application', 'Only the patient name', 'The type of tourniquet used only'], correctAnswer: 1, explanation: 'Document the TIME of tourniquet application (write it on the patient or tourniquet), the LOCATION on the limb, and the REASON for application. The time is critical because prolonged tourniquet application can lead to limb ischemia. Hospital staff need this information to determine the duration of ischemia.', area: 'trauma-management', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'core-tm-13', question: 'A patient with a crush injury to the lower extremity has been trapped for over 2 hours. Upon extrication, the EMS provider should be prepared for:', options: ['Immediate improvement in the patient condition', 'Crush syndrome with potential for hyperkalemia, cardiac arrhythmias, and renal failure', 'No significant complications', 'Only localized swelling'], correctAnswer: 1, explanation: 'Crush syndrome occurs when prolonged compression of large muscle masses releases toxic intracellular contents (especially potassium, myoglobin, and lactic acid) into the bloodstream upon release. This can cause life-threatening hyperkalemia (cardiac arrhythmias), myoglobinuria (renal failure), and hypovolemic shock. Aggressive IV fluid resuscitation before and after extrication is critical.', area: 'trauma-management', difficulty: 'hard', type: 'multiple-choice' },

  // === CORE: Oxygen Administration - New Category ===
  { id: 'core-oa-06', question: 'A full "D" size oxygen cylinder reads approximately how many psi?', options: ['500 psi', '1000 psi', '2000 psi', '3000 psi'], correctAnswer: 2, explanation: 'A full D-size oxygen cylinder reads approximately 2000 psi. The D cylinder holds about 350 liters of oxygen when full. To estimate remaining time: (psi reading × cylinder factor) ÷ flow rate. The cylinder factor for D cylinders is 0.16. Always check the gauge before departing on a call.', area: 'oxygen-administration', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'core-oa-07', question: 'A nasal cannula delivers oxygen at what concentration and flow rate?', options: ['24-44% at 1-6 liters per minute', '60-90% at 10-15 liters per minute', '80-100% at 12-15 liters per minute', '100% at any flow rate'], correctAnswer: 0, explanation: 'A nasal cannula delivers 24-44% oxygen at flow rates of 1-6 L/min. It is used for patients who need low to moderate supplemental oxygen. Each liter per minute adds approximately 4% above room air (21%). For example, 2 L/min delivers approximately 28% oxygen.', area: 'oxygen-administration', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'core-oa-08', question: 'A non-rebreather mask should be set to what flow rate to deliver 90-100% oxygen?', options: ['2-4 liters per minute', '6-8 liters per minute', '10-15 liters per minute', '1-2 liters per minute'], correctAnswer: 2, explanation: 'A non-rebreather mask requires 10-15 L/min flow to deliver 90-100% oxygen. The reservoir bag must remain at least two-thirds full during inspiration. Lower flow rates result in lower oxygen concentrations and may cause the patient to rebreathe exhaled air. This is the device of choice for critically ill or injured patients needing high-concentration oxygen.', area: 'oxygen-administration', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'core-oa-09', question: 'You have a D oxygen cylinder reading 1000 psi and you are administering oxygen at 5 L/min via nasal cannula. Approximately how long will the cylinder last?', options: ['About 16 minutes', 'About 32 minutes', 'About 60 minutes', 'About 90 minutes'], correctAnswer: 1, explanation: 'To calculate: remaining time = (gauge pressure × cylinder factor) ÷ flow rate. For a D cylinder: (1000 psi × 0.16) ÷ 5 L/min = 160 ÷ 5 = 32 minutes. Always calculate cylinder duration before transport to ensure adequate oxygen supply for the entire trip.', area: 'oxygen-administration', difficulty: 'hard', type: 'multiple-choice' },
  { id: 'core-oa-10', question: 'When should humidification be used with oxygen administration?', options: ['Never in the prehospital setting', 'When oxygen is delivered at flow rates above 4-6 L/min for extended periods', 'Only with non-rebreather masks', 'Only in cold weather'], correctAnswer: 1, explanation: 'Humidification should be considered when oxygen is delivered at flow rates above 4-6 L/min for extended periods. Dry oxygen can irritate the mucous membranes, dry secretions, and cause patient discomfort. For short-term or low-flow oxygen therapy, humidification is typically not necessary.', area: 'oxygen-administration', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'core-oa-11', question: 'A Venturi mask is used to deliver:', options: ['The highest possible oxygen concentration', 'A specific, precise oxygen concentration (24-50%)', 'Only humidified oxygen', 'Oxygen at the fastest flow rate'], correctAnswer: 1, explanation: 'A Venturi mask delivers a specific, precise oxygen concentration by using different color-coded adapters that entrain room air at calculated ratios. Available concentrations include 24%, 28%, 31%, 35%, 40%, and 50%. This is especially useful for COPD patients who require controlled oxygen delivery.', area: 'oxygen-administration', difficulty: 'hard', type: 'multiple-choice' },

  // === CORE: Spinal Immobilization - New Category ===
  { id: 'core-si-06', question: 'Which of the following is a validated criterion for clinically clearing a cervical spine in a trauma patient (using the Canadian C-Spine Rule)?', options: ['Any patient involved in a motor vehicle crash must be immobilized', 'Patients who are alert, sober, without distracting injuries, and have no midline cervical tenderness may be clinically cleared', 'Only X-ray can clear a cervical spine', 'All elderly patients must be immobilized regardless of findings'], correctAnswer: 1, explanation: 'The Canadian C-Spine Rule allows clinical clearance in alert (GCS 15), sober patients without dangerous mechanism or distracting injuries, who are able to rotate their neck 45 degrees left and right without pain. However, in the prehospital setting, most protocols require immobilization if any suspicion exists and clearance is typically done at the hospital.', area: 'spinal-immobilization', difficulty: 'hard', type: 'multiple-choice' },
  { id: 'core-si-07', question: 'When immobilizing a pediatric patient with a suspected spinal injury, which of the following is a special consideration?', options: ['Children do not need spinal immobilization', 'The relatively large head of a child may cause flexion on a standard backboard; padding under the shoulders is needed', 'Cervical collars are not made for children', 'Children always have spinal injuries'], correctAnswer: 1, explanation: 'Children have proportionally larger heads than adults, which can cause significant neck flexion when placed on a flat surface. To maintain neutral alignment, place padding under the shoulders (not the head) to prevent flexion. This is a critical pediatric spinal immobilization consideration.', area: 'spinal-immobilization', difficulty: 'hard', type: 'multiple-choice' },
  { id: 'core-si-08', question: 'A football player is injured on the field and is wearing a helmet. When should the helmet be removed?', options: ['Always remove the helmet immediately', 'Remove the helmet if it prevents proper airway management, does not fit snugly, or interferes with cervical collar application', 'Never remove a helmet in the field', 'Remove only if the patient requests it'], correctAnswer: 1, explanation: 'Remove the helmet if: it prevents adequate airway management, it does not hold the head securely, it prevents proper cervical collar fitting, or the face mask cannot be removed for airway access. If the helmet fits snugly and allows proper immobilization and airway access, it may be left in place. When removing, at least two rescuers are required to maintain in-line stabilization.', area: 'spinal-immobilization', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'core-si-09', question: 'When log-rolling a patient with suspected spinal injury onto a long spine board, the minimum number of rescuers needed is:', options: ['2', '3', '4', '5'], correctAnswer: 2, explanation: 'A minimum of 3 rescuers are needed for log-rolling: one at the head maintaining manual in-line stabilization and directing the roll, and two along the side of the patient to control the body during the roll. A fourth person is ideal to position the backboard, but three is the minimum for safety.', area: 'spinal-immobilization', difficulty: 'medium', type: 'multiple-choice' },

  // === CORE: Splinting and Bandaging - New Category ===
  { id: 'core-sb-06', question: 'When applying a traction splint for a suspected femur fracture, you should first:', options: ['Apply the traction splint before manual traction', 'Apply manual traction to stabilize the limb and reduce pain before applying the splint', 'Skip traction if the fracture is open', 'Twist the limb to align the bones first'], correctAnswer: 1, explanation: 'Before applying a traction splint, apply and maintain manual traction to stabilize the fracture, reduce pain, and minimize further tissue damage. Manual traction is maintained until the mechanical traction splint is secured and providing adequate traction. Never release manual traction until the splint is fully applied.', area: 'splinting-bandaging', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'core-sb-07', question: 'When splinting an angulated fracture, you should:', options: ['Always straighten the angulated bone before splinting', 'Splint the fracture in the position found unless there is no distal pulse, then attempt one gentle realignment', 'Force the bone back into alignment', 'Apply the splint only above the fracture site'], correctAnswer: 1, explanation: 'Splint fractures in the position found (position of function). The exception is when there is no distal pulse (neurovascular compromise), in which case one gentle attempt at realignment may be made to restore circulation. Document the presence or absence of distal pulses before and after splinting.', area: 'splinting-bandaging', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'core-sb-08', question: 'After applying a splint, you must check distal neurovascular status. This includes assessing:', options: ['Only skin color', 'Pulse, sensation, and motor function distal to the injury', 'Only the patient pain level', 'Only the skin temperature'], correctAnswer: 1, explanation: 'After splinting, check and document distal PMS (Pulse, Motor function, Sensation) before and after application. This ensures the splint is not compromising circulation or nerve function. Absence of a distal pulse after splinting is an emergency requiring immediate splint adjustment or removal.', area: 'splinting-bandaging', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'core-sb-09', question: 'A pressure dressing should be applied when:', options: ['A wound is bleeding and direct pressure alone is insufficient', 'There is a minor abrasion', 'The patient has an allergic reaction', 'There is a suspected fracture with no bleeding'], correctAnswer: 0, explanation: 'A pressure dressing is applied when a wound continues to bleed despite direct pressure. It consists of a bulky dressing placed directly over the wound, secured tightly with bandages to maintain continuous pressure. If blood soaks through, do not remove the dressing; add additional dressings on top and increase pressure.', area: 'splinting-bandaging', difficulty: 'easy', type: 'multiple-choice' },

  // === CORE: Patient Transport - Additional Questions ===
  { id: 'core-pt-07', question: 'When loading a stretcher into the ambulance using the loading mechanism, you should:', options: ['One person can handle it alone', 'Ensure at least two people are present: one operating the loading mechanism and one guiding the stretcher', 'Push the stretcher as fast as possible', 'Only the driver should load the stretcher'], correctAnswer: 1, explanation: 'Even with power loading mechanisms, at least two people should be present: one operating the controls and one guiding and stabilizing the stretcher. Never rely solely on the mechanical system without a spotter. Ensure the stretcher is properly locked into the mounting before releasing it.', area: 'patient-transport', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'core-pt-08', question: 'During ambulance transport, you notice a change in the patient condition. You should:', options: ['Wait until arrival at the hospital to assess', 'Immediately reassess the patient, intervene as needed, and notify the receiving facility', 'Pull over and call for another ambulance', 'Document the change and continue transport'], correctAnswer: 1, explanation: 'Any change in patient condition during transport requires immediate reassessment, appropriate intervention within your scope of practice, and notification of the receiving facility. Changes such as altered mental status, decreased SpO2, or hemodynamic instability may require modified treatment or expedited transport.', area: 'patient-transport', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'core-pt-09', question: 'A bariatric patient requires transport. Which of the following is most important?', options: ['Using a standard stretcher with more straps', 'Ensuring the stretcher and loading system are rated for the patient weight and having adequate personnel', 'Having the patient walk to the ambulance', 'Using a stair chair instead of a stretcher'], correctAnswer: 1, explanation: 'For bariatric patients, verify that the stretcher and power loading system have adequate weight capacity. Ensure sufficient personnel are available for safe lifting and transfer. Use bariatric equipment when available. Never exceed equipment weight limits as this can cause equipment failure and patient/provider injury.', area: 'patient-transport', difficulty: 'medium', type: 'multiple-choice' },

  // === CORE: Emergency Communication - Additional Questions ===
  { id: 'core-ec-06', question: 'When using the SBAR format to give a radio report to the hospital, the "Recommendation" section should include:', options: ['Your personal opinion about the diagnosis', 'What you are requesting or recommending, such as orders or a specific receiving area', 'The patient full name and address', 'A lengthy explanation of the dispatch information'], correctAnswer: 1, explanation: 'The Recommendation component of SBAR states what you are requesting or recommending: specific orders needed, a trauma activation, cardiac catheterization lab, or other resources. Keep it concise and focused. This is not the place for personal opinions or extensive background information.', area: 'emergency-communication', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'core-ec-07', question: 'During a radio transmission, you hear another unit communicating on the same channel. You should:', options: ['Transmit over them', 'Wait until the channel is clear before transmitting', 'Transmit louder to be heard over them', 'Switch to a different channel without authorization'], correctAnswer: 1, explanation: 'Radio etiquette requires waiting until the channel is clear before transmitting. Transmitting over another unit can cause interference and both messages may be lost. Listen first, then transmit when the channel is clear. This is especially critical during emergencies when important information is being relayed.', area: 'emergency-communication', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'core-ec-08', question: 'When receiving a verbal order from medical direction, the order is for "epinephrine 1:1000, 0.3 mg IM." You should:', options: ['Administer the medication immediately without repeating the order', 'Read back the complete order including medication name, concentration, dose, and route to confirm accuracy', 'Only repeat the medication name', 'Administer the medication and document later'], correctAnswer: 1, explanation: 'When receiving verbal orders, use closed-loop communication: read back the complete order including the medication name, concentration, dose, and route. This prevents errors such as confusing epinephrine 1:1000 with 1:10,000 (which would be given IV, not IM). Confirmation ensures both parties agree on the treatment plan.', area: 'emergency-communication', difficulty: 'medium', type: 'multiple-choice' },

  // === CORE: Safe Extrication - Additional Questions ===
  { id: 'core-se-06', question: 'Before beginning extrication operations on a vehicle, you should ensure the vehicle is stabilized by:', options: ['Turning off the engine only', 'Chocking the wheels, putting the vehicle in park, turning off the ignition, and disconnecting the battery', 'Only turning off the headlights', 'Letting the vehicle settle on its own'], correctAnswer: 1, explanation: 'Vehicle stabilization includes: chocking the wheels, putting the vehicle in park (or gear for manual), turning off the ignition, setting the parking brake, disconnecting the battery (negative terminal first), and ensuring the vehicle is on stable ground. This prevents vehicle movement and reduces fire risk during extrication.', area: 'safe-extrication', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'core-se-07', question: 'The Kendrick Extrication Device (KED) is primarily used for:', options: ['Immobilizing patients with femur fractures', 'Extricating patients from vehicles while maintaining spinal alignment', 'Carrying patients down stairs', 'Immobilizing pediatric patients only'], correctAnswer: 1, explanation: 'The KED is a short spinal immobilization device specifically designed for extricating patients from vehicles while maintaining spinal alignment. It wraps around the torso and head, providing immobilization during removal from a seated position. After extrication, the patient is transferred to a long spine board.', area: 'safe-extrication', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'core-se-08', question: 'When using the rapid extrication technique, the key principle is:', options: ['Speed is the only priority, regardless of technique', 'Maintain spinal alignment as much as possible while quickly moving the patient to safety', 'Always remove the patient through the window', 'Do not use a cervical collar during rapid extrication'], correctAnswer: 1, explanation: 'Rapid extrication prioritizes speed while maintaining the best possible spinal alignment. A cervical collar should still be applied if time permits. This technique is used when the scene is unsafe or the patient condition requires immediate removal. The goal is to move the patient as a unit with minimal spinal movement.', area: 'safe-extrication', difficulty: 'medium', type: 'multiple-choice' },

  // === CORE: Mass Casualty - Additional Questions ===
  { id: 'core-mc-06', question: 'In START triage, a patient who cannot walk, has a respiratory rate of 28, absent radial pulse, and is unconscious would be categorized as:', options: ['GREEN - Minor', 'YELLOW - Delayed', 'RED - Immediate', 'BLACK - Deceased/Expectant'], correctAnswer: 2, explanation: 'In START triage: the patient cannot walk (not GREEN), respiratory rate is 28 (above 30 = RED, but 28 is below that threshold), but absent radial pulse AND unconscious indicate poor perfusion. According to START, absent radial pulse OR capillary refill >2 sec categorizes the patient as RED (Immediate). This patient needs immediate life-saving intervention.', area: 'mass-casualty', difficulty: 'hard', type: 'multiple-choice' },
  { id: 'core-mc-07', question: 'In the Incident Command System, the role of the "Safety Officer" is to:', options: ['Provide direct patient care', 'Monitor the incident for safety hazards and has the authority to stop unsafe operations', 'Manage communication equipment', 'Assign patients to ambulances'], correctAnswer: 1, explanation: 'The Safety Officer monitors all aspects of the incident for safety concerns and has the authority to immediately stop any operation that presents an imminent danger to personnel. This role reports directly to the Incident Commander. Everyone on scene has the responsibility to maintain safety, but the Safety Officer has the specific authority to halt unsafe actions.', area: 'mass-casualty', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'core-mc-08', question: 'During a mass casualty incident, the treatment area should be established:', options: ['In the middle of the incident site', 'Upwind, uphill, and at a safe distance from the incident site', 'In the nearest hospital lobby', 'Wherever the most patients are located'], correctAnswer: 1, explanation: 'The treatment area should be established upwind and uphill from the incident to protect patients and providers from hazardous materials, smoke, or other environmental threats. It should be accessible to transport vehicles and large enough to accommodate all anticipated casualties. Mark areas clearly by triage color.', area: 'mass-casualty', difficulty: 'medium', type: 'multiple-choice' },

  // ========================================
  // COMMON COMPETENCIES - Additional Questions
  // ========================================

  // Infection Control - Additional
  { id: 'cc-ic-06', question: 'An EMS provider is exposed to a patient with suspected tuberculosis (TB). TB is primarily transmitted through:', options: ['Direct contact with blood', 'Airborne droplet nuclei from coughing or sneezing', 'Fecal-oral route', 'Vector-borne transmission'], correctAnswer: 1, explanation: 'TB is transmitted via airborne droplet nuclei (particles <5 microns) that remain suspended in the air for extended periods. When a person with active TB coughs, sneezes, or speaks, these particles can be inhaled by others. An N95 respirator (not a surgical mask) is required for protection against airborne pathogens like TB.', area: 'infection-control', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'cc-ic-07', question: 'After providing care to a patient with copious vomiting and diarrhea, the proper doffing sequence for PPE is:', options: ['Gloves, gown, mask, eye protection', 'Gloves, eye protection, gown, mask', 'Gown, gloves, mask, eye protection', 'Mask, gloves, eye protection, gown'], correctAnswer: 1, explanation: 'The correct doffing sequence is: gloves first (most contaminated), then eye protection, then gown, then mask last. This sequence minimizes contact with contaminated surfaces. Perform hand hygiene immediately after removing all PPE. Always remove PPE slowly and carefully to avoid contamination.', area: 'infection-control', difficulty: 'hard', type: 'multiple-choice' },
  { id: 'cc-ic-08', question: 'A patient with suspected meningococcal meningitis requires which level of respiratory protection for the EMS provider?', options: ['No protection needed', 'Surgical mask', 'N95 respirator or higher', 'Full-face respirator with P100 filters'], correctAnswer: 2, explanation: 'Meningococcal meningitis is transmitted through droplets. While a surgical mask provides some protection against droplets, the CDC recommends an N95 respirator when caring for patients with suspected meningococcal disease, especially during procedures that may generate aerosols. Droplet precautions plus standard precautions should be implemented.', area: 'infection-control', difficulty: 'hard', type: 'multiple-choice' },

  // Vital Signs - Additional
  { id: 'cc-vs-08', question: 'A patient has a blood pressure of 160/100 mmHg and a heart rate of 88 bpm. The pulse pressure is:', options: ['60 mmHg', '100 mmHg', '260 mmHg', '160 mmHg'], correctAnswer: 0, explanation: 'Pulse pressure = systolic BP - diastolic BP = 160 - 100 = 60 mmHg. Normal pulse pressure is 30-40 mmHg. A widened pulse pressure (>40) can indicate conditions like aortic regurgitation, hyperthyroidism, or atherosclerosis. A narrowed pulse pressure (<25) may indicate cardiac tamponade, tension pneumothorax, or hypovolemic shock.', area: 'vital-signs', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'cc-vs-09', question: 'A patient has vital signs showing BP 88/60 mmHg, HR 124 bpm, RR 28, SpO2 91%. These trending values most likely indicate:', options: ['Normal healthy adult values', 'Hypovolemic shock with compensatory tachycardia and hypotension', 'Anxiety only', 'Athletic conditioning'], correctAnswer: 1, explanation: 'These vital signs indicate shock: low BP (hypotension), high HR (compensatory tachycardia), elevated RR (compensatory tachypnea), and low SpO2. The body is attempting to compensate for inadequate perfusion. Hypotension is a LATE sign of shock - by the time BP drops, the patient has already lost significant blood volume or cardiac output.', area: 'vital-signs', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'cc-vs-10', question: 'A GCS score of 3 indicates:', options: ['Mild head injury', 'Moderate head injury', 'Severe head injury - the lowest possible score', 'No head injury'], correctAnswer: 2, explanation: 'A GCS of 3 is the lowest possible score and indicates no eye opening (1), no verbal response (1), and no motor response (1). This represents the most severe level of impaired consciousness and indicates a critical patient who needs immediate airway management and rapid transport. GCS ≤8 generally indicates the need for definitive airway management.', area: 'vital-signs', difficulty: 'easy', type: 'multiple-choice' },

  // Patient Assessment - Additional
  { id: 'cc-pa-07', question: 'You respond to a 65-year-old male with chest pain. During your assessment, he suddenly becomes unresponsive, stops breathing, and has no pulse. Your immediate action should be:', options: ['Obtain a 12-lead ECG', 'Begin CPR starting with chest compressions and apply the AED as soon as possible', 'Administer aspirin', 'Call the family for history'], correctAnswer: 1, explanation: 'When a patient becomes unresponsive with no breathing and no pulse, this is cardiac arrest. Immediately begin CPR starting with chest compressions and apply the AED as soon as available. Do not delay CPR for any other intervention. Every minute without CPR and defibrillation decreases survival by 7-10%.', area: 'patient-assessment', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'cc-pa-08', question: 'During the secondary assessment of a trauma patient, you palpate the abdomen and find it rigid and board-like. This finding suggests:', options: ['Normal abdomen', 'Peritonitis from internal bleeding or organ injury', 'Constipation', 'Muscle spasm only'], correctAnswer: 1, explanation: 'A rigid, board-like abdomen is a significant finding suggesting peritonitis, which often results from internal bleeding (hemoperitoneum) or a ruptured hollow organ. This is a surgical emergency. The rigidity is caused by inflammation of the peritoneal lining. Document this finding and prepare for rapid transport to a trauma center.', area: 'patient-assessment', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'cc-pa-09', question: 'When assessing a patient with a possible stroke, the Cincinnati Prehospital Stroke Scale evaluates which three areas?', options: ['Blood pressure, heart rate, respiratory rate', 'Facial droop, arm drift, and speech', 'Pupil response, grip strength, and orientation', 'Pain level, sensation, and movement'], correctAnswer: 1, explanation: 'The Cincinnati Prehospital Stroke Scale assesses three areas: Facial Droop (ask the patient to smile or show teeth), Arm Drift (ask the patient to close eyes and hold both arms out with palms up), and Speech (ask the patient to repeat a simple phrase). Any abnormality in one or more areas strongly suggests an acute stroke.', area: 'patient-assessment', difficulty: 'medium', type: 'multiple-choice' },

  // Basic Anatomy - Additional
  { id: 'cc-ba-06', question: 'Which type of shock is caused by widespread vasodilation due to a severe allergic reaction?', options: ['Cardiogenic shock', 'Hypovolemic shock', 'Distributive shock (anaphylactic)', 'Obstructive shock'], correctAnswer: 2, explanation: 'Anaphylactic shock is a type of distributive shock caused by massive vasodilation and increased capillary permeability from a severe allergic reaction. Other types of distributive shock include septic shock and neurogenic shock. Distributive shock involves a problem with vessel tone rather than pump failure (cardiogenic) or volume loss (hypovolemic).', area: 'basic-anatomy', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'cc-ba-07', question: 'The autonomic nervous system has two divisions. The sympathetic nervous system is responsible for:', options: ['Rest and digest functions', 'Fight or flight response', 'Only heart rate control', 'Only digestion'], correctAnswer: 1, explanation: 'The sympathetic nervous system triggers the "fight or flight" response: increased heart rate, blood pressure, and respiratory rate; pupil dilation; bronchodilation; and decreased digestive activity. The parasympathetic system controls "rest and digest" functions. In shock, the sympathetic system is activated to maintain perfusion to vital organs.', area: 'basic-anatomy', difficulty: 'easy', type: 'multiple-choice' },
  { id: 'cc-ba-08', question: 'Neurogenic shock is characterized by:', options: ['Increased heart rate and vasoconstriction', 'Hypotension with bradycardia due to loss of sympathetic tone from spinal cord injury', 'Hypertension and tachycardia', 'Normal vital signs with weakness'], correctAnswer: 1, explanation: 'Neurogenic shock occurs after spinal cord injury above T6, disrupting sympathetic outflow. This causes vasodilation (warm, dry skin) and unopposed parasympathetic activity (bradycardia), resulting in hypotension. Unlike hypovolemic shock (tachycardia, cool/clammy skin), neurogenic shock presents with hypotension, bradycardia, and warm/dry skin below the injury level.', area: 'basic-anatomy', difficulty: 'hard', type: 'multiple-choice' },

  // Medical Terminology - Additional
  { id: 'cc-mt-06', question: 'The combining form "cardio-" refers to the heart. "Myocarditis" therefore means:', options: ['Heart muscle tumor', 'Inflammation of the heart muscle', 'Enlargement of the heart', 'Hardening of the heart muscle'], correctAnswer: 1, explanation: 'Myocarditis: "myo" = muscle, "card" = heart, "itis" = inflammation. It means inflammation of the heart muscle. Understanding medical terminology by breaking words into component parts (prefix, root, suffix) helps EMS providers understand conditions even if they have not encountered the specific term before.', area: 'medical-terminology', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'cc-mt-07', question: 'The prefix "dys-" as in "dyspnea" means:', options: ['Without', 'Difficult or abnormal', 'Excessive', 'Below normal'], correctAnswer: 1, explanation: 'The prefix "dys-" means difficult, painful, or abnormal. Dyspnea = difficult breathing, dysphagia = difficult swallowing, dysrhythmia = abnormal rhythm. Do not confuse with "a-" or "an-" (without), "hyper-" (excessive), or "hypo-" (below normal).', area: 'medical-terminology', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'cc-mt-08', question: 'The term "hemorrhage" can be broken down as:', options: ['Hemo (blood) + rrhage (rupture/excessive flow)', 'Hemo (water) + rrhage (healing)', 'Hemo (heart) + rrhage (stopping)', 'Hem (half) + orrhage (flow)'], correctAnswer: 0, explanation: 'Hemorrhage: "hemo/hema" = blood, "-rrhage" = rupture or excessive flow. It means excessive bleeding. Other terms with "-rrhage" include menorrhagia (excessive menstrual bleeding). Terms with "hemo-" include hemoglobin, hematology, and hematuria (blood in urine).', area: 'medical-terminology', difficulty: 'medium', type: 'multiple-choice' },

  // ========================================
  // BASIC COMPETENCIES - Additional Questions
  // ========================================

  // Workplace Communication - Additional
  { id: 'bc-wc-06', question: 'You disagree with a team member about the best approach to manage a patient during a call. The appropriate action is:', options: ['Argue loudly in front of the patient', 'Discuss the disagreement privately and professionally, focusing on patient care', 'Ignore your concerns and do nothing', 'Report the team member to the supervisor immediately'], correctAnswer: 1, explanation: 'Disagreements should be handled privately and professionally, always keeping patient care as the focus. Discussing differences in front of the patient undermines confidence and professionalism. If the disagreement involves patient safety, address it immediately but respectfully using closed-loop communication principles.', area: 'workplace-communication', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'bc-wc-07', question: 'In the EMS chain of command, if you have a concern about a protocol that your immediate supervisor has not addressed, you should:', options: ['Ignore the concern', 'Follow the chain of command by escalating to the next level of supervision', 'Bypass all supervisors and contact the media', 'Quit your job immediately'], correctAnswer: 1, explanation: 'The chain of command exists to ensure concerns are addressed through proper channels. If your immediate supervisor does not address a legitimate concern, escalate to the next level. Never ignore safety concerns, but also do not bypass the chain of command unnecessarily. This systematic approach ensures accountability and resolution.', area: 'workplace-communication', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'bc-wc-08', question: 'When giving a verbal report during patient handoff at the hospital, you should:', options: ['Include every detail from the call, no matter how minor', 'Provide a concise, structured report with the most critical information first', 'Only hand over the paperwork without speaking', 'Rush through the report because the hospital staff is busy'], correctAnswer: 1, explanation: 'A good handoff report is concise and structured (e.g., SBAR format), leading with the most critical information. Include patient identification, chief complaint, relevant assessment findings, treatment provided, and response to treatment. Avoid unnecessary details but ensure all safety-critical information is communicated. Allow time for questions.', area: 'workplace-communication', difficulty: 'easy', type: 'multiple-choice' },

  // Professionalism - Additional
  { id: 'bc-pr-06', question: 'A patient with a valid Do Not Resuscitate (DNR) order goes into cardiac arrest. The EMS provider should:', options: ['Ignore the DNR and begin resuscitation', 'Honor the DNR order after verifying it is valid and applicable to the current situation', 'Contact the family for permission to resuscitate', 'Begin CPR but stop after 5 minutes'], correctAnswer: 1, explanation: 'If a valid DNR order is present, it should be honored. Verify the DNR is: (1) a valid legal document, (2) applicable to the current situation, and (3) belongs to this patient. Different jurisdictions have different DNR formats (e.g., bracelets, wallet cards, forms). When in doubt about the validity, begin resuscitation while seeking clarification.', area: 'professionalism', difficulty: 'hard', type: 'multiple-choice' },
  { id: 'bc-pr-07', question: 'Informed consent requires that the patient understands all of the following EXCEPT:', options: ['The nature of the treatment or procedure', 'The risks and benefits of the treatment', 'The provider personal religious beliefs', 'The right to refuse treatment'], correctAnswer: 2, explanation: 'Informed consent requires that the patient understands: the nature of the procedure, the risks and benefits, the alternatives, and the right to refuse. The provider personal religious beliefs are not relevant to informed consent. A patient must have capacity (be alert, oriented, and able to make rational decisions) for consent to be valid.', area: 'professionalism', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'bc-pr-08', question: 'An EMS provider scope of practice is defined by:', options: ['The individual provider personal preference', 'The national or regional regulatory body and local medical direction', 'The hospital staff', 'The patient family'], correctAnswer: 1, explanation: 'Scope of practice is defined by the national or regional regulatory authority (e.g., DOH in the Philippines) and local medical direction protocols. It outlines what skills and interventions an EMS provider at a specific certification level is authorized to perform. Operating outside your scope of practice is illegal and may result in disciplinary action and liability.', area: 'professionalism', difficulty: 'medium', type: 'multiple-choice' },

  // Occupational Safety - Additional
  { id: 'bc-osh-06', question: 'An EMS provider is exposed to blood from a patient with known HIV. Post-exposure prophylaxis (PEP) should ideally be started within:', options: ['72 hours', '24-36 hours (the sooner the better)', '1 week', '1 month'], correctAnswer: 1, explanation: 'PEP for HIV exposure should be started as soon as possible, ideally within 1-2 hours of exposure, and no later than 72 hours. The earlier PEP is started, the more effective it is. After a significant exposure, immediately wash the area, report to the designated infection control officer, and seek immediate medical evaluation for PEP consideration.', area: 'occupational-safety', difficulty: 'hard', type: 'multiple-choice' },
  { id: 'bc-osh-07', question: 'Signs of critical incident stress in an EMS provider may include:', options: ['Only physical symptoms', 'Difficulty sleeping, irritability, difficulty concentrating, and emotional withdrawal', 'Increased productivity and energy', 'No noticeable changes'], correctAnswer: 1, explanation: 'Critical incident stress can manifest as sleep disturbances, irritability, difficulty concentrating, emotional withdrawal, anxiety, depression, flashbacks, and changes in appetite or substance use. These are normal reactions to abnormal events. CISM programs, peer support, and professional counseling can help providers process traumatic experiences.', area: 'occupational-safety', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'bc-osh-08', question: 'When selecting PPE for a call involving a patient with active tuberculosis, the minimum respiratory protection is:', options: ['Surgical mask', 'N95 respirator', 'No mask needed if staying 6 feet away', 'Cloth face covering'], correctAnswer: 1, explanation: 'An N95 respirator (or higher-level respiratory protection) is required when caring for patients with suspected or confirmed TB. Surgical masks do not filter the small airborne droplet nuclei that transmit TB. The N95 filters at least 95% of airborne particles. Always perform a seal check when donning an N95 respirator.', area: 'occupational-safety', difficulty: 'medium', type: 'multiple-choice' },

  // Problem Solving - Additional
  { id: 'bc-ps-06', question: 'You arrive at a scene with limited resources and two critical patients. There is only one ambulance available. The most appropriate action is:', options: ['Treat both patients equally at the scene', 'Triage the patients, treat the most critical first, and request additional resources immediately', 'Leave both patients and go get help', 'Flip a coin to decide which patient to treat first'], correctAnswer: 1, explanation: 'With limited resources and multiple critical patients, apply triage principles: rapidly assess both patients, prioritize the one with the most life-threatening but treatable condition, and immediately request additional resources (additional ambulances, mutual aid). This approach maximizes the benefit of available resources.', area: 'problem-solving', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'bc-ps-07', question: 'A patient refuses treatment but their condition appears life-threatening. The EMS provider should:', options: ['Force treatment on the patient', 'Assess the patient decision-making capacity, explain the risks of refusal, and document thoroughly', 'Leave immediately without documentation', 'Call the police to force treatment'], correctAnswer: 1, explanation: 'A competent adult has the right to refuse treatment. Assess their capacity (alert, oriented, understanding consequences), clearly explain the risks of refusal, involve family if appropriate, consult medical direction, and document everything including the patient stated understanding of risks. Force treatment only if the patient lacks capacity and implied consent applies.', area: 'problem-solving', difficulty: 'hard', type: 'multiple-choice' },
  { id: 'bc-ps-08', question: 'During a call, you realize you have made a medication error. The ethical response is to:', options: ['Hide the error and hope no one notices', 'Immediately report the error, monitor the patient, and document accurately', 'Blame a partner for the mistake', 'Only report it if the patient has an adverse reaction'], correctAnswer: 1, explanation: 'Medication errors must be reported immediately, regardless of whether the patient shows adverse effects. The patient must be closely monitored, the error documented accurately, and medical direction notified. Honest reporting is both ethical and legally protective. Attempting to cover up errors can lead to patient harm, loss of trust, and more severe legal consequences.', area: 'problem-solving', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'bc-ps-09', question: 'You respond to a call where the patient is a family member. You should:', options: ['Provide care as you would for any patient, but disclose the relationship to your partner and consider requesting another unit', 'Refuse to provide any care', 'Provide care without telling anyone about the relationship', 'Take over all decision-making because you know the patient best'], correctAnswer: 0, explanation: 'When treating a family member, disclose the relationship to your partner and consider requesting another unit if feasible. Emotional involvement can impair clinical judgment. Provide the same standard of care as you would for any patient, but be aware that personal relationships may affect objectivity. Some protocols restrict treating close family members.', area: 'problem-solving', difficulty: 'medium', type: 'multiple-choice' },
  { id: 'bc-ps-10', question: 'You and your partner respond to a call, but your partner is visibly impaired (alcohol or drugs). Your first action should be:', options: ['Ignore it and proceed with the call', 'Remove your partner from patient care, notify your supervisor immediately, and ensure patient safety', 'Complete the call and report later', 'Ask the patient if they are okay with it'], correctAnswer: 1, explanation: 'An impaired partner must be immediately removed from patient care for safety reasons. Notify your supervisor/chief immediately and ensure another provider is available to assist. Providing care while impaired endangers the patient, the provider, and the public. This is a patient safety issue that requires immediate action regardless of personal relationships.', area: 'problem-solving', difficulty: 'hard', type: 'multiple-choice' },
];
